fn string_member(name: &str) -> PathMember {
    PathMember::test_string(name.to_string(), false, Casing::Sensitive)
}

fn test_record(fields: Vec<(&str, Value)>) -> Record {
    let mut record = Record::new();
    for (name, value) in fields {
        record.push(name, value);
    }
    record
}

fn make_numeric_list_pipeline_call_program(decl_id: DeclId, count: Option<i64>) -> HirProgram {
    let mut stmts = vec![HirStmt::LoadValue {
        dst: RegId::new(0),
        val: Box::new(Value::list(
            vec![
                Value::int(10, Span::test_data()),
                Value::int(20, Span::test_data()),
                Value::int(30, Span::test_data()),
            ],
            Span::test_data(),
        )),
    }];
    let positional = if let Some(count) = count {
        stmts.push(HirStmt::LoadLiteral {
            dst: RegId::new(2),
            lit: HirLiteral::Int(count),
        });
        vec![RegId::new(2)]
    } else {
        Vec::new()
    };

    stmts.push(HirStmt::Call {
        decl_id,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            positional,
            pipeline_input: Some(RegId::new(0)),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: RegId::new(1) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 3,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_numeric_list_in_place_scalar_call_program(decl_id: DeclId) -> HirProgram {
    let mut stmts = vec![HirStmt::LoadLiteral {
        dst: RegId::new(0),
        lit: HirLiteral::List { capacity: 3 },
    }];
    for value in [10, 20, 30] {
        stmts.push(HirStmt::LoadLiteral {
            dst: RegId::new(1),
            lit: HirLiteral::Int(value),
        });
        stmts.push(HirStmt::ListPush {
            src_dst: RegId::new(0),
            item: RegId::new(1),
        });
    }
    stmts.push(HirStmt::Call {
        decl_id,
        src_dst: RegId::new(0),
        args: HirCallArgs {
            pipeline_input: Some(RegId::new(0)),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: RegId::new(0) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 2,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_runtime_numeric_list_pipeline_call_program(
    decl_id: DeclId,
    append_decl: DeclId,
    random_decl: DeclId,
    trailing_values: &[i64],
) -> HirProgram {
    let mut stmts = vec![HirStmt::LoadValue {
        dst: RegId::new(0),
        val: Box::new(Value::list(
            trailing_values
                .iter()
                .map(|value| Value::int(*value, Span::test_data()))
                .collect(),
            Span::test_data(),
        )),
    }];

    stmts.push(HirStmt::Call {
        decl_id: random_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs::default(),
    });
    stmts.push(HirStmt::Call {
        decl_id: append_decl,
        src_dst: RegId::new(2),
        args: HirCallArgs {
            pipeline_input: Some(RegId::new(0)),
            positional: vec![RegId::new(1)],
            ..HirCallArgs::default()
        },
    });

    stmts.push(HirStmt::Call {
        decl_id,
        src_dst: RegId::new(3),
        args: HirCallArgs {
            pipeline_input: Some(RegId::new(2)),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: RegId::new(3) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 4,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

