fn make_int_list_builder_transform_runtime_get_program(
    transform_decl: DeclId,
    random_decl: DeclId,
    get_decl: DeclId,
    values: &[i64],
    in_place_get: bool,
) -> HirProgram {
    let mut stmts = vec![HirStmt::LoadLiteral {
        dst: RegId::new(0),
        lit: HirLiteral::List {
            capacity: values.len(),
        },
    }];

    let mut next_reg = 2;
    for value in values {
        let item_reg = RegId::new(next_reg);
        next_reg += 1;
        stmts.push(HirStmt::LoadLiteral {
            dst: item_reg,
            lit: HirLiteral::Int(*value),
        });
        stmts.push(HirStmt::ListPush {
            src_dst: RegId::new(0),
            item: item_reg,
        });
    }

    stmts.push(HirStmt::Call {
        decl_id: transform_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            pipeline_input: Some(RegId::new(0)),
            ..HirCallArgs::default()
        },
    });

    let index_reg = RegId::new(next_reg);
    next_reg += 1;
    stmts.push(HirStmt::Call {
        decl_id: random_decl,
        src_dst: index_reg,
        args: HirCallArgs::default(),
    });

    let result_reg = if in_place_get {
        RegId::new(1)
    } else {
        let reg = RegId::new(next_reg);
        next_reg += 1;
        reg
    };
    stmts.push(HirStmt::Call {
        decl_id: get_decl,
        src_dst: result_reg,
        args: HirCallArgs {
            positional: vec![index_reg],
            pipeline_input: Some(RegId::new(1)),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: result_reg },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: next_reg,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

