fn make_numeric_list_predicate_call_program(
    command_decl: DeclId,
    command_name: &str,
    values: &[i64],
    threshold: i64,
) -> (HirProgram, HashMap<DeclId, String>) {
    let closure_block_id = nu_protocol::BlockId::new(1);
    let list_values = values
        .iter()
        .map(|value| Value::int(*value, Span::test_data()))
        .collect::<Vec<_>>();
    let main = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: vec![
                HirStmt::LoadValue {
                    dst: RegId::new(0),
                    val: Box::new(Value::list(list_values, Span::test_data())),
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(2),
                    lit: HirLiteral::Closure(closure_block_id),
                },
                HirStmt::Call {
                    decl_id: command_decl,
                    src_dst: RegId::new(1),
                    args: HirCallArgs {
                        positional: vec![RegId::new(2)],
                        pipeline_input: Some(RegId::new(0)),
                        ..HirCallArgs::default()
                    },
                },
            ],
            terminator: HirTerminator::Return { src: RegId::new(1) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 3,
        file_count: 0,
    };
    let closure = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: vec![
                HirStmt::LoadVariable {
                    dst: RegId::new(0),
                    var_id: IN_VARIABLE_ID,
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(1),
                    lit: HirLiteral::Int(threshold),
                },
                HirStmt::BinaryOp {
                    lhs_dst: RegId::new(0),
                    op: Operator::Comparison(Comparison::GreaterThan),
                    rhs: RegId::new(1),
                },
            ],
            terminator: HirTerminator::Return { src: RegId::new(0) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 2,
        file_count: 0,
    };
    (
        HirProgram::new(
            main,
            HashMap::from([(closure_block_id, closure)]),
            Vec::new(),
            None,
        ),
        HashMap::from([(command_decl, command_name.to_string())]),
    )
}

