fn make_float_literal_list_builder_pipeline_call_program(
    decl_id: DeclId,
    values: &[f64],
) -> HirProgram {
    let value_count = values.len();
    let mut stmts = vec![HirStmt::LoadLiteral {
        dst: RegId::new(0),
        lit: HirLiteral::List {
            capacity: value_count,
        },
    }];

    for (index, value) in values.iter().enumerate() {
        let item_reg = RegId::new(u32::try_from(index).expect("test index fits in u32") + 2);
        stmts.push(HirStmt::LoadLiteral {
            dst: item_reg,
            lit: HirLiteral::Float(*value),
        });
        stmts.push(HirStmt::ListPush {
            src_dst: RegId::new(0),
            item: item_reg,
        });
    }

    stmts.push(HirStmt::Call {
        decl_id,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            pipeline_input: Some(RegId::new(0)),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: RegId::new(1) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: u32::try_from(value_count).expect("test float-list length fits in u32") + 2,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_float_literal_list_builder_transform_consumer_program(
    transform_decl: DeclId,
    transform_count: Option<i64>,
    consumer_decl: DeclId,
    values: &[f64],
) -> HirProgram {
    let mut stmts = vec![HirStmt::LoadLiteral {
        dst: RegId::new(0),
        lit: HirLiteral::List {
            capacity: values.len(),
        },
    }];

    let mut next_reg = 2;
    for value in values {
        let item_reg = RegId::new(next_reg);
        next_reg += 1;
        stmts.push(HirStmt::LoadLiteral {
            dst: item_reg,
            lit: HirLiteral::Float(*value),
        });
        stmts.push(HirStmt::ListPush {
            src_dst: RegId::new(0),
            item: item_reg,
        });
    }

    let positional = if let Some(count) = transform_count {
        let count_reg = RegId::new(next_reg);
        next_reg += 1;
        stmts.push(HirStmt::LoadLiteral {
            dst: count_reg,
            lit: HirLiteral::Int(count),
        });
        vec![count_reg]
    } else {
        Vec::new()
    };

    stmts.push(HirStmt::Call {
        decl_id: transform_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            positional,
            pipeline_input: Some(RegId::new(0)),
            ..HirCallArgs::default()
        },
    });

    let consumer_result_reg = RegId::new(next_reg);
    next_reg += 1;
    stmts.push(HirStmt::Call {
        decl_id: consumer_decl,
        src_dst: consumer_result_reg,
        args: HirCallArgs {
            pipeline_input: Some(RegId::new(1)),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return {
                src: consumer_result_reg,
            },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: next_reg,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_float_literal_list_builder_transform_two_consumers_program(
    transform_decl: DeclId,
    transform_count: Option<i64>,
    first_consumer_decl: DeclId,
    second_consumer_decl: DeclId,
    values: &[f64],
) -> HirProgram {
    let mut program = make_float_literal_list_builder_transform_consumer_program(
        transform_decl,
        transform_count,
        first_consumer_decl,
        values,
    );

    let block = &mut program.main.blocks[0];
    let previous_result = match block.terminator {
        HirTerminator::Return { src } => src,
        _ => unreachable!("test helper creates a return terminator"),
    };
    let second_result = RegId::new(program.main.register_count);
    program.main.register_count += 1;
    block.stmts.push(HirStmt::Call {
        decl_id: second_consumer_decl,
        src_dst: second_result,
        args: HirCallArgs {
            pipeline_input: Some(previous_result),
            ..HirCallArgs::default()
        },
    });
    block.terminator = HirTerminator::Return { src: second_result };

    program
}

fn make_float_literal_list_builder_find_consumer_program(
    find_decl: DeclId,
    needle: f64,
    consumer_decl: DeclId,
    values: &[f64],
) -> HirProgram {
    let mut program = make_float_literal_list_builder_transform_consumer_program(
        find_decl,
        None,
        consumer_decl,
        values,
    );

    let block = &mut program.main.blocks[0];
    let consumer_call = block
        .stmts
        .pop()
        .expect("test helper creates a consumer call");
    let find_call = block
        .stmts
        .pop()
        .expect("test helper creates a transform call");
    let needle_reg = RegId::new(program.main.register_count);
    program.main.register_count += 1;

    block.stmts.push(HirStmt::LoadLiteral {
        dst: needle_reg,
        lit: HirLiteral::Float(needle),
    });
    let HirStmt::Call {
        decl_id,
        src_dst,
        mut args,
    } = find_call
    else {
        unreachable!("test helper creates a transform call")
    };
    args.positional = vec![needle_reg];
    block.stmts.push(HirStmt::Call {
        decl_id,
        src_dst,
        args,
    });
    block.stmts.push(consumer_call);

    program
}

