fn make_string_index_of_range_program(
    decl_id: DeclId,
    value: &str,
    needle: &str,
    start: Option<i64>,
    end: Option<i64>,
    inclusion: RangeInclusion,
    flags: Vec<Vec<u8>>,
) -> HirProgram {
    make_string_index_of_range_program_with_step(
        decl_id, value, needle, start, 1, end, inclusion, flags,
    )
}

fn make_string_index_of_range_program_with_step(
    decl_id: DeclId,
    value: &str,
    needle: &str,
    start: Option<i64>,
    step: i64,
    end: Option<i64>,
    inclusion: RangeInclusion,
    flags: Vec<Vec<u8>>,
) -> HirProgram {
    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: vec![
                HirStmt::LoadValue {
                    dst: RegId::new(0),
                    val: Box::new(Value::string(value, Span::test_data())),
                },
                HirStmt::LoadValue {
                    dst: RegId::new(2),
                    val: Box::new(Value::string(needle, Span::test_data())),
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(3),
                    lit: start.map_or(HirLiteral::Nothing, HirLiteral::Int),
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(4),
                    lit: HirLiteral::Int(step),
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(5),
                    lit: end.map_or(HirLiteral::Nothing, HirLiteral::Int),
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(6),
                    lit: HirLiteral::Range {
                        start: RegId::new(3),
                        step: RegId::new(4),
                        end: RegId::new(5),
                        inclusion,
                    },
                },
                HirStmt::Call {
                    decl_id,
                    src_dst: RegId::new(1),
                    args: HirCallArgs {
                        positional: vec![RegId::new(2)],
                        named: vec![(b"range".to_vec(), RegId::new(6))],
                        pipeline_input: Some(RegId::new(0)),
                        flags,
                        ..HirCallArgs::default()
                    },
                },
            ],
            terminator: HirTerminator::Return { src: RegId::new(1) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 7,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

