fn make_string_list_builder_join_then_starts_with_program(
    join_decl: DeclId,
    starts_with_decl: DeclId,
    values: &[&str],
    separator: &str,
    prefix: &str,
) -> HirProgram {
    let value_count = values.len();
    let value_count_u32 = u32::try_from(value_count).expect("test string-list length fits in u32");
    let mut stmts = vec![HirStmt::LoadLiteral {
        dst: RegId::new(0),
        lit: HirLiteral::List {
            capacity: value_count,
        },
    }];

    for (index, value) in values.iter().enumerate() {
        let item_reg = RegId::new(u32::try_from(index).expect("test index fits in u32") + 2);
        stmts.push(HirStmt::LoadValue {
            dst: item_reg,
            val: Box::new(Value::string(*value, Span::test_data())),
        });
        stmts.push(HirStmt::ListPush {
            src_dst: RegId::new(0),
            item: item_reg,
        });
    }

    let separator_reg = RegId::new(value_count_u32 + 2);
    let prefix_reg = RegId::new(value_count_u32 + 3);
    let result_reg = RegId::new(value_count_u32 + 4);
    stmts.push(HirStmt::LoadValue {
        dst: separator_reg,
        val: Box::new(Value::string(separator, Span::test_data())),
    });
    stmts.push(HirStmt::Call {
        decl_id: join_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            positional: vec![separator_reg],
            pipeline_input: Some(RegId::new(0)),
            ..HirCallArgs::default()
        },
    });
    stmts.push(HirStmt::LoadValue {
        dst: prefix_reg,
        val: Box::new(Value::string(prefix, Span::test_data())),
    });
    stmts.push(HirStmt::Call {
        decl_id: starts_with_decl,
        src_dst: result_reg,
        args: HirCallArgs {
            positional: vec![prefix_reg],
            pipeline_input: Some(RegId::new(1)),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: result_reg },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: value_count_u32 + 5,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

