fn make_string_list_builder_index_of_join_then_starts_with_program(
    index_of_decl: DeclId,
    join_decl: DeclId,
    starts_with_decl: DeclId,
    values: &[&str],
    needle: &str,
    expected_prefix: &str,
    flags: Vec<Vec<u8>>,
    range: Option<(Option<i64>, Option<i64>, RangeInclusion)>,
) -> HirProgram {
    let value_count = values.len();
    let value_count_u32 = u32::try_from(value_count).expect("test string-list length fits in u32");
    let mut stmts = vec![HirStmt::LoadLiteral {
        dst: RegId::new(0),
        lit: HirLiteral::List {
            capacity: value_count,
        },
    }];

    for (index, value) in values.iter().enumerate() {
        let item_reg = RegId::new(u32::try_from(index).expect("test index fits in u32") + 2);
        stmts.push(HirStmt::LoadValue {
            dst: item_reg,
            val: Box::new(Value::string(*value, Span::test_data())),
        });
        stmts.push(HirStmt::ListPush {
            src_dst: RegId::new(0),
            item: item_reg,
        });
    }

    let needle_reg = RegId::new(value_count_u32 + 2);
    let mut next_reg = needle_reg.get() + 1;
    stmts.push(HirStmt::LoadValue {
        dst: needle_reg,
        val: Box::new(Value::string(needle, Span::test_data())),
    });

    let mut named = Vec::new();
    if let Some((start, end, inclusion)) = range {
        let start_reg = RegId::new(next_reg);
        let step_reg = RegId::new(next_reg + 1);
        let end_reg = RegId::new(next_reg + 2);
        let range_reg = RegId::new(next_reg + 3);
        next_reg += 4;
        stmts.push(HirStmt::LoadLiteral {
            dst: start_reg,
            lit: start.map_or(HirLiteral::Nothing, HirLiteral::Int),
        });
        stmts.push(HirStmt::LoadLiteral {
            dst: step_reg,
            lit: HirLiteral::Int(1),
        });
        stmts.push(HirStmt::LoadLiteral {
            dst: end_reg,
            lit: end.map_or(HirLiteral::Nothing, HirLiteral::Int),
        });
        stmts.push(HirStmt::LoadLiteral {
            dst: range_reg,
            lit: HirLiteral::Range {
                start: start_reg,
                step: step_reg,
                end: end_reg,
                inclusion,
            },
        });
        named.push((b"range".to_vec(), range_reg));
    }

    stmts.push(HirStmt::Call {
        decl_id: index_of_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            positional: vec![needle_reg],
            named,
            flags,
            pipeline_input: Some(RegId::new(0)),
            ..HirCallArgs::default()
        },
    });

    let separator_reg = RegId::new(next_reg);
    let expected_prefix_reg = RegId::new(next_reg + 1);
    stmts.push(HirStmt::LoadValue {
        dst: separator_reg,
        val: Box::new(Value::string("-", Span::test_data())),
    });
    stmts.push(HirStmt::Call {
        decl_id: join_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            positional: vec![separator_reg],
            pipeline_input: Some(RegId::new(1)),
            ..HirCallArgs::default()
        },
    });
    stmts.push(HirStmt::LoadValue {
        dst: expected_prefix_reg,
        val: Box::new(Value::string(expected_prefix, Span::test_data())),
    });
    stmts.push(HirStmt::Call {
        decl_id: starts_with_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            positional: vec![expected_prefix_reg],
            pipeline_input: Some(RegId::new(1)),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: RegId::new(1) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: expected_prefix_reg.get() + 1,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_string_list_builder_pipeline_call_program(decl_id: DeclId, values: &[&str]) -> HirProgram {
    let value_count = values.len();
    let value_count_u32 = u32::try_from(value_count).expect("test string-list length fits in u32");
    let mut stmts = vec![HirStmt::LoadLiteral {
        dst: RegId::new(0),
        lit: HirLiteral::List {
            capacity: value_count,
        },
    }];

    for (index, value) in values.iter().enumerate() {
        let item_reg = RegId::new(u32::try_from(index).expect("test index fits in u32") + 2);
        stmts.push(HirStmt::LoadValue {
            dst: item_reg,
            val: Box::new(Value::string(*value, Span::test_data())),
        });
        stmts.push(HirStmt::ListPush {
            src_dst: RegId::new(0),
            item: item_reg,
        });
    }

    stmts.push(HirStmt::Call {
        decl_id,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            pipeline_input: Some(RegId::new(0)),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: RegId::new(1) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: value_count_u32 + 2,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_split_list_string_get_join_then_starts_with_program(
    split_decl: DeclId,
    get_decl: DeclId,
    join_decl: DeclId,
    starts_with_decl: DeclId,
    values: &[&str],
    separator: &str,
    flags: Vec<&str>,
    split_mode: Option<&str>,
    group_index: i64,
    join_separator: &str,
    prefix: &str,
) -> HirProgram {
    let mut next_reg = 2u32;
    let mut stmts = vec![HirStmt::LoadValue {
        dst: RegId::new(0),
        val: Box::new(Value::list(
            values
                .iter()
                .map(|value| Value::string(*value, Span::test_data()))
                .collect(),
            Span::test_data(),
        )),
    }];

    let separator_reg = RegId::new(next_reg);
    next_reg += 1;
    stmts.push(HirStmt::LoadValue {
        dst: separator_reg,
        val: Box::new(Value::string(separator, Span::test_data())),
    });

    let mut named = Vec::new();
    if let Some(split_mode) = split_mode {
        let split_mode_reg = RegId::new(next_reg);
        next_reg += 1;
        stmts.push(HirStmt::LoadValue {
            dst: split_mode_reg,
            val: Box::new(Value::string(split_mode, Span::test_data())),
        });
        named.push((b"split".to_vec(), split_mode_reg));
    }

    stmts.push(HirStmt::Call {
        decl_id: split_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            positional: vec![separator_reg],
            named,
            flags: flags
                .into_iter()
                .map(|flag| flag.as_bytes().to_vec())
                .collect(),
            pipeline_input: Some(RegId::new(0)),
            ..HirCallArgs::default()
        },
    });

    let group_index_reg = RegId::new(next_reg);
    next_reg += 1;
    stmts.push(HirStmt::LoadLiteral {
        dst: group_index_reg,
        lit: HirLiteral::Int(group_index),
    });
    stmts.push(HirStmt::Call {
        decl_id: get_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            positional: vec![group_index_reg],
            pipeline_input: Some(RegId::new(1)),
            ..HirCallArgs::default()
        },
    });

    let join_separator_reg = RegId::new(next_reg);
    next_reg += 1;
    stmts.push(HirStmt::LoadValue {
        dst: join_separator_reg,
        val: Box::new(Value::string(join_separator, Span::test_data())),
    });
    stmts.push(HirStmt::Call {
        decl_id: join_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            positional: vec![join_separator_reg],
            pipeline_input: Some(RegId::new(1)),
            ..HirCallArgs::default()
        },
    });

    let prefix_reg = RegId::new(next_reg);
    next_reg += 1;
    let starts_with_reg = RegId::new(next_reg);
    next_reg += 1;
    stmts.push(HirStmt::LoadValue {
        dst: prefix_reg,
        val: Box::new(Value::string(prefix, Span::test_data())),
    });
    stmts.push(HirStmt::Call {
        decl_id: starts_with_decl,
        src_dst: starts_with_reg,
        args: HirCallArgs {
            positional: vec![prefix_reg],
            pipeline_input: Some(RegId::new(1)),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return {
                src: starts_with_reg,
            },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: next_reg,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

