fn make_record_list_compact_length_program(
    compact_decl: DeclId,
    length_decl: DeclId,
    rows: Vec<Record>,
    columns: &[&str],
    remove_empty: bool,
) -> HirProgram {
    let mut stmts = vec![HirStmt::LoadLiteral {
        dst: RegId::new(0),
        lit: HirLiteral::List {
            capacity: rows.len(),
        },
    }];

    let mut next_reg = 3u32;
    for row in rows {
        let row_reg = RegId::new(next_reg);
        next_reg += 1;
        stmts.push(HirStmt::LoadValue {
            dst: row_reg,
            val: Box::new(Value::record(row, Span::test_data())),
        });
        stmts.push(HirStmt::ListPush {
            src_dst: RegId::new(0),
            item: row_reg,
        });
    }

    let mut positional = Vec::new();
    for column in columns {
        let column_reg = RegId::new(next_reg);
        next_reg += 1;
        stmts.push(HirStmt::LoadLiteral {
            dst: column_reg,
            lit: HirLiteral::String(column.as_bytes().to_vec()),
        });
        positional.push(column_reg);
    }

    stmts.push(HirStmt::Call {
        decl_id: compact_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            positional,
            flags: remove_empty
                .then(|| b"empty".to_vec())
                .into_iter()
                .collect(),
            pipeline_input: Some(RegId::new(0)),
            ..HirCallArgs::default()
        },
    });
    stmts.push(HirStmt::Call {
        decl_id: length_decl,
        src_dst: RegId::new(2),
        args: HirCallArgs {
            pipeline_input: Some(RegId::new(1)),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: RegId::new(2) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: next_reg,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_string_list_builder_item_access_then_starts_with_program(
    access_decl: DeclId,
    starts_with_decl: DeclId,
    values: &[&str],
    index: Option<i64>,
    prefix: &str,
) -> HirProgram {
    let value_count = values.len();
    let value_count_u32 = u32::try_from(value_count).expect("test string-list length fits in u32");
    let mut stmts = vec![HirStmt::LoadLiteral {
        dst: RegId::new(0),
        lit: HirLiteral::List {
            capacity: value_count,
        },
    }];

    for (index, value) in values.iter().enumerate() {
        let item_reg = RegId::new(u32::try_from(index).expect("test index fits in u32") + 2);
        stmts.push(HirStmt::LoadValue {
            dst: item_reg,
            val: Box::new(Value::string(*value, Span::test_data())),
        });
        stmts.push(HirStmt::ListPush {
            src_dst: RegId::new(0),
            item: item_reg,
        });
    }

    let index_reg = index.map(|raw_index| {
        let reg = RegId::new(value_count_u32 + 2);
        stmts.push(HirStmt::LoadLiteral {
            dst: reg,
            lit: HirLiteral::Int(raw_index),
        });
        reg
    });
    let prefix_reg = RegId::new(value_count_u32 + 2 + u32::from(index_reg.is_some()));
    stmts.push(HirStmt::Call {
        decl_id: access_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            positional: index_reg.into_iter().collect(),
            pipeline_input: Some(RegId::new(0)),
            ..HirCallArgs::default()
        },
    });
    stmts.push(HirStmt::LoadValue {
        dst: prefix_reg,
        val: Box::new(Value::string(prefix, Span::test_data())),
    });
    stmts.push(HirStmt::Call {
        decl_id: starts_with_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            positional: vec![prefix_reg],
            pipeline_input: Some(RegId::new(1)),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: RegId::new(1) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: prefix_reg.get() + 1,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_string_list_builder_transform_join_then_starts_with_program(
    transform_decl: DeclId,
    join_decl: DeclId,
    starts_with_decl: DeclId,
    values: &[&str],
    count: Option<i64>,
    flags: Vec<Vec<u8>>,
    prefix: &str,
) -> HirProgram {
    let value_count = values.len();
    let value_count_u32 = u32::try_from(value_count).expect("test string-list length fits in u32");
    let mut stmts = vec![HirStmt::LoadLiteral {
        dst: RegId::new(0),
        lit: HirLiteral::List {
            capacity: value_count,
        },
    }];

    for (index, value) in values.iter().enumerate() {
        let item_reg = RegId::new(u32::try_from(index).expect("test index fits in u32") + 2);
        stmts.push(HirStmt::LoadValue {
            dst: item_reg,
            val: Box::new(Value::string(*value, Span::test_data())),
        });
        stmts.push(HirStmt::ListPush {
            src_dst: RegId::new(0),
            item: item_reg,
        });
    }

    let count_reg = count.map(|raw_count| {
        let reg = RegId::new(value_count_u32 + 2);
        stmts.push(HirStmt::LoadLiteral {
            dst: reg,
            lit: HirLiteral::Int(raw_count),
        });
        reg
    });
    let separator_reg = RegId::new(value_count_u32 + 2 + u32::from(count_reg.is_some()));
    let prefix_reg = RegId::new(separator_reg.get() + 1);
    stmts.push(HirStmt::Call {
        decl_id: transform_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            positional: count_reg.into_iter().collect(),
            flags,
            pipeline_input: Some(RegId::new(0)),
            ..HirCallArgs::default()
        },
    });
    stmts.push(HirStmt::LoadValue {
        dst: separator_reg,
        val: Box::new(Value::string("-", Span::test_data())),
    });
    stmts.push(HirStmt::Call {
        decl_id: join_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            positional: vec![separator_reg],
            pipeline_input: Some(RegId::new(1)),
            ..HirCallArgs::default()
        },
    });
    stmts.push(HirStmt::LoadValue {
        dst: prefix_reg,
        val: Box::new(Value::string(prefix, Span::test_data())),
    });
    stmts.push(HirStmt::Call {
        decl_id: starts_with_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            positional: vec![prefix_reg],
            pipeline_input: Some(RegId::new(1)),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: RegId::new(1) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: prefix_reg.get() + 1,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

