fn make_record_columns_transform_join_starts_with_program(
    columns_decl: DeclId,
    transform_decl: DeclId,
    join_decl: DeclId,
    starts_with_decl: DeclId,
    transform_arg: Option<&str>,
    expected_prefix: &str,
) -> HirProgram {
    let mut record = Record::new();
    record.push("pid", Value::int(7, Span::test_data()));
    record.push("cpu", Value::int(2, Span::test_data()));
    record.push("ok", Value::bool(true, Span::test_data()));

    let mut stmts = vec![
        HirStmt::LoadValue {
            dst: RegId::new(0),
            val: Box::new(Value::record(record, Span::test_data())),
        },
        HirStmt::Call {
            decl_id: columns_decl,
            src_dst: RegId::new(1),
            args: HirCallArgs {
                pipeline_input: Some(RegId::new(0)),
                ..HirCallArgs::default()
            },
        },
    ];

    let mut next_reg = 2;
    let transform_positional = if let Some(arg) = transform_arg {
        let arg_reg = RegId::new(next_reg);
        next_reg += 1;
        stmts.push(HirStmt::LoadValue {
            dst: arg_reg,
            val: Box::new(Value::string(arg, Span::test_data())),
        });
        vec![arg_reg]
    } else {
        Vec::new()
    };

    let transform_result_reg = RegId::new(next_reg);
    next_reg += 1;
    stmts.push(HirStmt::Call {
        decl_id: transform_decl,
        src_dst: transform_result_reg,
        args: HirCallArgs {
            positional: transform_positional,
            pipeline_input: Some(RegId::new(1)),
            ..HirCallArgs::default()
        },
    });

    let join_separator_reg = RegId::new(next_reg);
    next_reg += 1;
    stmts.push(HirStmt::LoadValue {
        dst: join_separator_reg,
        val: Box::new(Value::string(",", Span::test_data())),
    });
    let join_result_reg = RegId::new(next_reg);
    next_reg += 1;
    stmts.push(HirStmt::Call {
        decl_id: join_decl,
        src_dst: join_result_reg,
        args: HirCallArgs {
            positional: vec![join_separator_reg],
            pipeline_input: Some(transform_result_reg),
            ..HirCallArgs::default()
        },
    });

    let prefix_reg = RegId::new(next_reg);
    next_reg += 1;
    stmts.push(HirStmt::LoadValue {
        dst: prefix_reg,
        val: Box::new(Value::string(expected_prefix, Span::test_data())),
    });
    let starts_with_reg = RegId::new(next_reg);
    next_reg += 1;
    stmts.push(HirStmt::Call {
        decl_id: starts_with_decl,
        src_dst: starts_with_reg,
        args: HirCallArgs {
            positional: vec![prefix_reg],
            pipeline_input: Some(join_result_reg),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return {
                src: starts_with_reg,
            },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: next_reg,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_record_transpose_get_field_program(
    transpose_decl: DeclId,
    get_decl: DeclId,
    record: Record,
    row_index: i64,
    field_name: &str,
    ignore_titles: bool,
) -> HirProgram {
    let mut stmts = vec![
        HirStmt::LoadValue {
            dst: RegId::new(0),
            val: Box::new(Value::record(record, Span::test_data())),
        },
        HirStmt::LoadValue {
            dst: RegId::new(2),
            val: Box::new(Value::string(
                if ignore_titles { "val" } else { "key" },
                Span::test_data(),
            )),
        },
    ];
    let mut transpose_args = HirCallArgs {
        positional: vec![RegId::new(2)],
        pipeline_input: Some(RegId::new(0)),
        ..HirCallArgs::default()
    };
    if ignore_titles {
        transpose_args.flags = vec![b"ignore-titles".to_vec()];
    } else {
        stmts.push(HirStmt::LoadValue {
            dst: RegId::new(3),
            val: Box::new(Value::string("value", Span::test_data())),
        });
        transpose_args.positional.push(RegId::new(3));
    }
    stmts.extend([
        HirStmt::Call {
            decl_id: transpose_decl,
            src_dst: RegId::new(1),
            args: transpose_args,
        },
        HirStmt::LoadLiteral {
            dst: RegId::new(4),
            lit: HirLiteral::Int(row_index),
        },
        HirStmt::Call {
            decl_id: get_decl,
            src_dst: RegId::new(5),
            args: HirCallArgs {
                positional: vec![RegId::new(4)],
                pipeline_input: Some(RegId::new(1)),
                ..HirCallArgs::default()
            },
        },
        HirStmt::LoadValue {
            dst: RegId::new(6),
            val: Box::new(Value::string(field_name, Span::test_data())),
        },
        HirStmt::Call {
            decl_id: get_decl,
            src_dst: RegId::new(7),
            args: HirCallArgs {
                positional: vec![RegId::new(6)],
                pipeline_input: Some(RegId::new(5)),
                ..HirCallArgs::default()
            },
        },
    ]);

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: RegId::new(7) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 8,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_record_transpose_get_field_then_starts_with_program(
    transpose_decl: DeclId,
    get_decl: DeclId,
    starts_with_decl: DeclId,
) -> HirProgram {
    let record = test_record(vec![
        ("pid", Value::int(7, Span::test_data())),
        ("comm", Value::string("nu", Span::test_data())),
    ]);
    let mut hir = make_record_transpose_get_field_program(
        transpose_decl,
        get_decl,
        record,
        1,
        "value",
        false,
    );
    let block = &mut hir.main.blocks[0];
    block.stmts.push(HirStmt::LoadValue {
        dst: RegId::new(8),
        val: Box::new(Value::string("nu", Span::test_data())),
    });
    block.stmts.push(HirStmt::Call {
        decl_id: starts_with_decl,
        src_dst: RegId::new(9),
        args: HirCallArgs {
            positional: vec![RegId::new(8)],
            pipeline_input: Some(RegId::new(7)),
            ..HirCallArgs::default()
        },
    });
    block.terminator = HirTerminator::Return { src: RegId::new(9) };
    hir.main.register_count = 10;
    hir
}

