#[test]
fn test_lower_load_value_duration_as_const() {
    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: vec![HirStmt::LoadValue {
                dst: RegId::new(0),
                val: Box::new(Value::duration(1234, Span::test_data())),
            }],
            terminator: HirTerminator::Return { src: RegId::new(0) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 1,
        file_count: 0,
    };
    let hir = HirProgram::new(func, HashMap::new(), vec![], None);

    let result = lower_hir_to_mir_with_hints(
        &hir,
        None,
        &HashMap::new(),
        None,
        &HashMap::new(),
        &HashMap::new(),
    )
    .expect("duration load value should lower");

    assert!(matches!(
        result.program.main.blocks[0].instructions.as_slice(),
        [MirInst::Copy {
            src: MirValue::Const(1234),
            ..
        }]
    ));
}

#[test]
fn test_lower_first_on_numeric_list_gets_first_element() {
    let first_decl = DeclId::new(78);
    let hir = make_numeric_list_pipeline_call_program(first_decl, None);
    let decl_names = HashMap::from([(first_decl, "first".to_string())]);

    let result = lower_hir_to_mir_with_hints(
        &hir,
        None,
        &decl_names,
        None,
        &HashMap::new(),
        &HashMap::new(),
    )
    .expect("first should lower on stack-backed numeric lists");

    assert!(
        result
            .program
            .main
            .blocks
            .iter()
            .flat_map(|block| block.instructions.iter())
            .any(|inst| matches!(
                inst,
                MirInst::ListGet {
                    idx: MirValue::Const(0),
                    ..
                }
            )),
        "expected first to lower through ListGet at index 0"
    );
    compile_mir_to_ebpf_with_hints(&result.program, None, Some(&result.type_hints))
        .expect("first on stack-backed numeric list should compile through codegen");
}

#[test]
fn test_lower_last_on_numeric_list_gets_length_minus_one() {
    let last_decl = DeclId::new(79);
    let hir = make_numeric_list_pipeline_call_program(last_decl, None);
    let decl_names = HashMap::from([(last_decl, "last".to_string())]);

    let result = lower_hir_to_mir_with_hints(
        &hir,
        None,
        &decl_names,
        None,
        &HashMap::new(),
        &HashMap::new(),
    )
    .expect("last should lower on stack-backed numeric lists");
    let instructions = result
        .program
        .main
        .blocks
        .iter()
        .flat_map(|block| block.instructions.iter())
        .collect::<Vec<_>>();

    assert!(
        instructions
            .iter()
            .any(|inst| matches!(inst, MirInst::ListLen { .. })),
        "expected last to compute the list length"
    );
    assert!(
        instructions.iter().any(|inst| matches!(
            inst,
            MirInst::BinOp {
                op: BinOpKind::Sub,
                rhs: MirValue::Const(1),
                ..
            }
        )),
        "expected last to subtract one from the list length"
    );
    assert!(
        instructions.iter().any(|inst| matches!(
            inst,
            MirInst::ListGet {
                idx: MirValue::VReg(_),
                ..
            }
        )),
        "expected last to lower through dynamic ListGet"
    );
    compile_mir_to_ebpf_with_hints(&result.program, None, Some(&result.type_hints))
        .expect("last on stack-backed numeric list should compile through codegen");
}

fn assert_returned_scalar_i64_or_const(result: &MirLoweringResult, expected_const: i64) {
    let return_value = result
        .program
        .main
        .blocks
        .iter()
        .find_map(|block| match &block.terminator {
            MirInst::Return { val: Some(value) } => Some(value),
            _ => None,
        })
        .expect("expected scalar result to be returned");

    match return_value {
        MirValue::Const(value) => assert_eq!(
            *value, expected_const,
            "expected scalar constant return value"
        ),
        MirValue::VReg(vreg) => assert_eq!(
            result.type_hints.main.get(vreg),
            Some(&MirType::I64),
            "expected scalar result vreg to have an i64 type hint"
        ),
        other => panic!("expected scalar return value, got {other:?}"),
    }
}

#[test]
fn test_lower_first_on_in_place_numeric_list_returns_scalar_result() {
    let first_decl = DeclId::new(80);
    let hir = make_numeric_list_in_place_scalar_call_program(first_decl);
    let decl_names = HashMap::from([(first_decl, "first".to_string())]);
    let hir_types = crate::compiler::hir_type_infer::infer_hir_types(&hir, &decl_names)
        .expect("source-like first HIR should type-check");
    let probe_ctx = ProbeContext::new(EbpfProgramType::Kprobe, "ksys_read");

    let mut result = lower_hir_to_mir_with_hints(
        &hir,
        Some(&probe_ctx),
        &decl_names,
        Some(&hir_types),
        &HashMap::new(),
        &HashMap::new(),
    )
    .expect("first should lower when the source IR reuses the list register as src_dst");

    optimize_with_ssa_hints(
        &mut result.program.main,
        Some(&probe_ctx),
        &mut result.type_hints.main,
        &result.type_hints.main_stack_slots,
        &result.type_hints.generic_map_value_types,
    );
    assert_returned_scalar_i64_or_const(&result, 10);
    compile_mir_to_ebpf_with_hints(&result.program, Some(&probe_ctx), Some(&result.type_hints))
        .expect("optimized in-place first should compile through codegen");
}

