#[test]
fn test_lower_seq_date_rejects_unsupported_forms() {
    let scenarios = [
        (
            "missing begin-date",
            vec![("end-date", HirLiteral::String(b"2020-01-03".to_vec()))],
            Vec::new(),
            "seq date requires explicit --begin-date",
        ),
        (
            "missing range selector",
            vec![("begin-date", HirLiteral::String(b"2020-01-01".to_vec()))],
            Vec::new(),
            "seq date requires explicit --end-date, --days, or --periods",
        ),
        (
            "input format mismatch",
            vec![
                ("begin-date", HirLiteral::String(b"2020-01-01".to_vec())),
                ("end-date", HirLiteral::String(b"2020-01-03".to_vec())),
                ("input-format", HirLiteral::String(b"%m/%d/%Y".to_vec())),
            ],
            Vec::new(),
            "seq date --begin-date does not match --input-format",
        ),
        (
            "non-string output format",
            vec![
                ("begin-date", HirLiteral::String(b"2020-01-01".to_vec())),
                ("end-date", HirLiteral::String(b"2020-01-03".to_vec())),
                ("output-format", HirLiteral::Int(1)),
            ],
            Vec::new(),
            "seq date --output-format requires a compile-time string literal",
        ),
        (
            "unsupported flag",
            vec![
                ("begin-date", HirLiteral::String(b"2020-01-01".to_vec())),
                ("end-date", HirLiteral::String(b"2020-01-03".to_vec())),
            ],
            vec!["foo"],
            "seq date --foo is not supported",
        ),
        (
            "zero increment",
            vec![
                ("begin-date", HirLiteral::String(b"2020-01-01".to_vec())),
                ("end-date", HirLiteral::String(b"2020-01-03".to_vec())),
                ("increment", HirLiteral::Int(0)),
            ],
            Vec::new(),
            "seq date --increment requires a positive duration",
        ),
        (
            "negative duration increment",
            vec![
                ("begin-date", HirLiteral::String(b"2020-01-01".to_vec())),
                ("end-date", HirLiteral::String(b"2020-01-03".to_vec())),
                ("increment", HirLiteral::Duration(-1_000_000_000)),
            ],
            Vec::new(),
            "seq date --increment requires a positive duration",
        ),
        (
            "zero days",
            vec![
                ("begin-date", HirLiteral::String(b"2020-01-01".to_vec())),
                ("days", HirLiteral::Int(0)),
            ],
            Vec::new(),
            "seq date --days requires a positive integer",
        ),
        (
            "negative periods",
            vec![
                ("begin-date", HirLiteral::String(b"2020-01-01".to_vec())),
                ("periods", HirLiteral::Int(-1)),
            ],
            Vec::new(),
            "seq date --periods requires a positive integer",
        ),
        (
            "periods over capacity",
            vec![
                ("begin-date", HirLiteral::String(b"2020-01-01".to_vec())),
                ("periods", HirLiteral::Int(61)),
            ],
            Vec::new(),
            "seq date output exceeds fixed string-list capacity 60",
        ),
        (
            "over capacity",
            vec![
                ("begin-date", HirLiteral::String(b"2020-01-01".to_vec())),
                ("end-date", HirLiteral::String(b"2020-03-15".to_vec())),
            ],
            Vec::new(),
            "seq date output exceeds fixed string-list capacity 60",
        ),
    ];

    for (index, (context, named_args, flags, expected_error)) in scenarios.into_iter().enumerate() {
        let seq_date_decl = DeclId::new(790 + index);
        let hir = make_seq_date_program(seq_date_decl, &named_args, &flags);
        let decl_names = HashMap::from([(seq_date_decl, "seq date".to_string())]);

        let err = match lower_hir_to_mir_with_hints(
            &hir,
            None,
            &decl_names,
            None,
            &HashMap::new(),
            &HashMap::new(),
        ) {
            Ok(_) => panic!("seq date should reject {context}"),
            Err(err) => err,
        };

        assert!(
            err.to_string().contains(expected_error),
            "unexpected error for {context}: {err}"
        );
    }
}

