fn make_bits_binary_program_with_endian(
    bits_decl: DeclId,
    input: i64,
    target: i64,
    endian: Option<&str>,
) -> HirProgram {
    let mut stmts = vec![
        HirStmt::LoadLiteral {
            dst: RegId::new(0),
            lit: HirLiteral::Int(input),
        },
        HirStmt::LoadLiteral {
            dst: RegId::new(1),
            lit: HirLiteral::Int(target),
        },
    ];
    let named = if let Some(endian) = endian {
        stmts.push(HirStmt::LoadLiteral {
            dst: RegId::new(2),
            lit: HirLiteral::String(endian.as_bytes().to_vec()),
        });
        vec![(b"endian".to_vec(), RegId::new(2))]
    } else {
        Vec::new()
    };
    let result_reg = RegId::new(if endian.is_some() { 3 } else { 2 });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: {
                stmts.push(HirStmt::Call {
                    decl_id: bits_decl,
                    src_dst: result_reg,
                    args: HirCallArgs {
                        pipeline_input: Some(RegId::new(0)),
                        positional: vec![RegId::new(1)],
                        named,
                        ..HirCallArgs::default()
                    },
                });
                stmts
            },
            terminator: HirTerminator::Return { src: result_reg },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: if endian.is_some() { 4 } else { 3 },
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

