fn make_bits_shift_value_list_program(
    bits_decl: DeclId,
    values: Vec<Value>,
    shift_count: i64,
    signed: bool,
    number_bytes: Option<i64>,
) -> HirProgram {
    let mut stmts = vec![
        HirStmt::LoadValue {
            dst: RegId::new(0),
            val: Box::new(Value::list(values, Span::test_data())),
        },
        HirStmt::LoadLiteral {
            dst: RegId::new(1),
            lit: HirLiteral::Int(shift_count),
        },
    ];
    let named = if let Some(number_bytes) = number_bytes {
        stmts.push(HirStmt::LoadLiteral {
            dst: RegId::new(2),
            lit: HirLiteral::Int(number_bytes),
        });
        vec![(b"number-bytes".to_vec(), RegId::new(2))]
    } else {
        Vec::new()
    };

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: {
                stmts.push(HirStmt::Call {
                    decl_id: bits_decl,
                    src_dst: RegId::new(3),
                    args: HirCallArgs {
                        pipeline_input: Some(RegId::new(0)),
                        positional: vec![RegId::new(1)],
                        named,
                        flags: signed.then(|| b"signed".to_vec()).into_iter().collect(),
                        ..HirCallArgs::default()
                    },
                });
                stmts
            },
            terminator: HirTerminator::Return { src: RegId::new(3) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 4,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

