#[test]
fn test_lower_math_mode_on_known_integer_list_materializes_sorted_modes() {
    let mode_decl = DeclId::new(525);
    let sum_decl = DeclId::new(526);
    let hir = make_integer_list_two_call_program(mode_decl, sum_decl, &[5, 1, 5, 2, 1]);
    let decl_names = HashMap::from([
        (mode_decl, "math mode".to_string()),
        (sum_decl, "math sum".to_string()),
    ]);

    let result = lower_hir_to_mir_with_hints(
        &hir,
        None,
        &decl_names,
        None,
        &HashMap::new(),
        &HashMap::new(),
    )
    .expect("math mode should lower compile-time known integer-list input");
    let expected_modes = [1i64, 5]
        .into_iter()
        .flat_map(|value| value.to_le_bytes())
        .collect::<Vec<_>>();

    assert!(
        result
            .readonly_globals
            .iter()
            .any(|global| global.data == expected_modes),
        "expected math mode to materialize sorted mode values"
    );
    compile_mir_to_ebpf_with_hints(&result.program, None, Some(&result.type_hints))
        .expect("math mode output consumed by math sum should compile through codegen");
}

#[test]
fn test_lower_math_mode_on_empty_integer_list_returns_empty_list() {
    let mode_decl = DeclId::new(527);
    let length_decl = DeclId::new(528);
    let hir = make_integer_list_two_call_program(mode_decl, length_decl, &[]);
    let decl_names = HashMap::from([
        (mode_decl, "math mode".to_string()),
        (length_decl, "length".to_string()),
    ]);

    let result = lower_hir_to_mir_with_hints(
        &hir,
        None,
        &decl_names,
        None,
        &HashMap::new(),
        &HashMap::new(),
    )
    .expect("math mode should return an empty list for empty input");

    assert!(
        result
            .program
            .main
            .blocks
            .iter()
            .flat_map(|block| block.instructions.iter())
            .any(|inst| matches!(inst, MirInst::ListNew { max_len: 0, .. })),
        "expected math mode on empty input to allocate an empty numeric list"
    );
    compile_mir_to_ebpf_with_hints(&result.program, None, Some(&result.type_hints))
        .expect("empty math mode output consumed by length should compile through codegen");
}

#[test]
fn test_lower_math_mode_on_runtime_stack_numeric_list_uses_bounded_counts() {
    let mode_decl = DeclId::new(540);
    let length_decl = DeclId::new(541);
    let append_decl = DeclId::new(542);
    let random_decl = DeclId::new(543);
    let hir = make_runtime_numeric_list_two_call_program(
        mode_decl,
        length_decl,
        append_decl,
        random_decl,
        &[5, 1, 5],
    );
    let decl_names = HashMap::from([
        (mode_decl, "math mode".to_string()),
        (length_decl, "length".to_string()),
        (append_decl, "append".to_string()),
        (random_decl, "random int".to_string()),
    ]);

    let result = lower_hir_to_mir_with_hints(
        &hir,
        None,
        &decl_names,
        None,
        &HashMap::new(),
        &HashMap::new(),
    )
    .expect("math mode should lower runtime-valued stack-backed numeric-list input");
    let instructions = result
        .program
        .main
        .blocks
        .iter()
        .flat_map(|block| block.instructions.iter())
        .collect::<Vec<_>>();

    assert!(
        instructions
            .iter()
            .any(|inst| matches!(inst, MirInst::ListNew { max_len: 4, .. })),
        "expected runtime math mode to allocate bounded four-item stack lists"
    );
    assert!(
        instructions.iter().any(|inst| matches!(
            inst,
            MirInst::BinOp {
                op: BinOpKind::Gt,
                ..
            }
        )),
        "expected runtime math mode to sort and update max counts"
    );
    assert!(
        instructions.iter().any(|inst| matches!(
            inst,
            MirInst::BinOp {
                op: BinOpKind::Eq,
                ..
            }
        )),
        "expected runtime math mode to count values and select modes"
    );
    compile_mir_to_ebpf_with_hints(&result.program, None, Some(&result.type_hints))
        .expect("runtime math mode output consumed by length should compile through codegen");
}

#[test]
fn test_lower_math_mode_on_dynamic_length_stack_numeric_list() {
    let where_decl = DeclId::new(544);
    let mode_decl = DeclId::new(545);
    let length_decl = DeclId::new(546);
    let closure_block_id = nu_protocol::BlockId::new(1);

    let main = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: vec![
                HirStmt::LoadLiteral {
                    dst: RegId::new(0),
                    lit: HirLiteral::List { capacity: 3 },
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(1),
                    lit: HirLiteral::Int(10),
                },
                HirStmt::ListPush {
                    src_dst: RegId::new(0),
                    item: RegId::new(1),
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(2),
                    lit: HirLiteral::Int(20),
                },
                HirStmt::ListPush {
                    src_dst: RegId::new(0),
                    item: RegId::new(2),
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(3),
                    lit: HirLiteral::Closure(closure_block_id),
                },
                HirStmt::Call {
                    decl_id: where_decl,
                    src_dst: RegId::new(4),
                    args: HirCallArgs {
                        positional: vec![RegId::new(3)],
                        pipeline_input: Some(RegId::new(0)),
                        ..HirCallArgs::default()
                    },
                },
                HirStmt::Call {
                    decl_id: mode_decl,
                    src_dst: RegId::new(5),
                    args: HirCallArgs {
                        pipeline_input: Some(RegId::new(4)),
                        ..HirCallArgs::default()
                    },
                },
                HirStmt::Call {
                    decl_id: length_decl,
                    src_dst: RegId::new(6),
                    args: HirCallArgs {
                        pipeline_input: Some(RegId::new(5)),
                        ..HirCallArgs::default()
                    },
                },
            ],
            terminator: HirTerminator::Return { src: RegId::new(6) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 7,
        file_count: 0,
    };
    let closure = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: vec![HirStmt::LoadLiteral {
                dst: RegId::new(0),
                lit: HirLiteral::Bool(true),
            }],
            terminator: HirTerminator::Return { src: RegId::new(0) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 1,
        file_count: 0,
    };
    let hir = HirProgram::new(
        main,
        HashMap::from([(closure_block_id, closure)]),
        Vec::new(),
        None,
    );
    let decl_names = HashMap::from([
        (where_decl, "where".to_string()),
        (mode_decl, "math mode".to_string()),
        (length_decl, "length".to_string()),
    ]);

    let result = lower_hir_to_mir_with_hints(
        &hir,
        None,
        &decl_names,
        None,
        &HashMap::new(),
        &HashMap::new(),
    )
    .expect("math mode should lower dynamic-length stack-backed numeric-list input");
    assert!(
        result
            .program
            .main
            .blocks
            .iter()
            .flat_map(|block| block.instructions.iter())
            .any(|inst| matches!(inst, MirInst::ListLen { .. })),
        "expected dynamic-length math mode to preserve runtime length guards"
    );
    compile_mir_to_ebpf_with_hints(&result.program, None, Some(&result.type_hints)).expect(
        "dynamic-length math mode output consumed by length should compile through codegen",
    );
}

