fn make_math_abs_list_sum_program(
    abs_decl: DeclId,
    sum_decl: DeclId,
    values: Vec<i64>,
) -> HirProgram {
    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: vec![
                HirStmt::LoadValue {
                    dst: RegId::new(0),
                    val: Box::new(Value::list(
                        values
                            .into_iter()
                            .map(|value| Value::int(value, Span::test_data()))
                            .collect(),
                        Span::test_data(),
                    )),
                },
                HirStmt::Call {
                    decl_id: abs_decl,
                    src_dst: RegId::new(1),
                    args: HirCallArgs {
                        pipeline_input: Some(RegId::new(0)),
                        ..HirCallArgs::default()
                    },
                },
                HirStmt::Call {
                    decl_id: sum_decl,
                    src_dst: RegId::new(2),
                    args: HirCallArgs {
                        pipeline_input: Some(RegId::new(1)),
                        ..HirCallArgs::default()
                    },
                },
            ],
            terminator: HirTerminator::Return { src: RegId::new(2) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 3,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_math_abs_list_program(abs_decl: DeclId, values: Vec<i64>) -> HirProgram {
    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: vec![
                HirStmt::LoadValue {
                    dst: RegId::new(0),
                    val: Box::new(Value::list(
                        values
                            .into_iter()
                            .map(|value| Value::int(value, Span::test_data()))
                            .collect(),
                        Span::test_data(),
                    )),
                },
                HirStmt::Call {
                    decl_id: abs_decl,
                    src_dst: RegId::new(1),
                    args: HirCallArgs {
                        pipeline_input: Some(RegId::new(0)),
                        ..HirCallArgs::default()
                    },
                },
            ],
            terminator: HirTerminator::Return { src: RegId::new(1) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 2,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

#[test]
fn test_lower_math_integer_identity_commands_on_known_integer_inputs() {
    for (offset, command_name) in [(0, "math ceil"), (1, "math floor"), (2, "math round")] {
        let decl = DeclId::new(271 + offset);
        let hir = make_math_abs_program(decl, -7);
        let decl_names = HashMap::from([(decl, command_name.to_string())]);

        let result = lower_hir_to_mir_with_hints(
            &hir,
            None,
            &decl_names,
            None,
            &HashMap::new(),
            &HashMap::new(),
        )
        .unwrap_or_else(|err| panic!("{command_name} should lower integer input: {err}"));

        assert!(
            result
                .program
                .main
                .blocks
                .iter()
                .flat_map(|block| block.instructions.iter())
                .any(|inst| matches!(
                    inst,
                    MirInst::Copy {
                        src: MirValue::Const(-7),
                        ..
                    }
                )),
            "expected {command_name} to preserve the integer input"
        );
        compile_mir_to_ebpf_with_hints(&result.program, None, Some(&result.type_hints))
            .unwrap_or_else(|err| panic!("{command_name} should compile through codegen: {err}"));
    }
}

