#[test]
fn test_lower_bits_shift_signed_i64_on_known_integer_lists() {
    for (offset, command_name, values, expected_values) in [
        (0, "bits shl", vec![4i64, 3, 2], vec![8i64, 6, 4]),
        (1, "bits shr", vec![-16i64, -8, 7], vec![-8i64, -4, 3]),
    ] {
        let bits_decl = DeclId::new(7010 + offset);
        let sum_decl = DeclId::new(7020 + offset);
        let hir = make_bits_shift_signed_i64_list_sum_program(bits_decl, sum_decl, &values, 1);
        let decl_names = HashMap::from([
            (bits_decl, command_name.to_string()),
            (sum_decl, "math sum".to_string()),
        ]);

        let result = lower_hir_to_mir_with_hints(
            &hir,
            None,
            &decl_names,
            None,
            &HashMap::new(),
            &HashMap::new(),
        )
        .unwrap_or_else(|err| {
            panic!(
                "{command_name} --signed --number-bytes 8 should lower integer-list input: {err}"
            )
        });
        let expected = expected_values
            .into_iter()
            .flat_map(|value| value.to_le_bytes())
            .collect::<Vec<_>>();

        assert!(
            result
                .readonly_globals
                .iter()
                .any(|global| global.data == expected),
            "expected {command_name} --signed --number-bytes 8 to materialize the shifted integer list"
        );
        compile_mir_to_ebpf_with_hints(&result.program, None, Some(&result.type_hints))
            .unwrap_or_else(|err| panic!("{command_name} should compile through codegen: {err}"));
    }
}

