fn make_runtime_math_unary_list_length_program(
    command_decl: DeclId,
    length_decl: DeclId,
    random_decl: DeclId,
) -> HirProgram {
    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: vec![
                HirStmt::LoadLiteral {
                    dst: RegId::new(0),
                    lit: HirLiteral::List { capacity: 1 },
                },
                HirStmt::Call {
                    decl_id: random_decl,
                    src_dst: RegId::new(1),
                    args: HirCallArgs::default(),
                },
                HirStmt::ListPush {
                    src_dst: RegId::new(0),
                    item: RegId::new(1),
                },
                HirStmt::Call {
                    decl_id: command_decl,
                    src_dst: RegId::new(2),
                    args: HirCallArgs {
                        pipeline_input: Some(RegId::new(0)),
                        ..HirCallArgs::default()
                    },
                },
                HirStmt::Call {
                    decl_id: length_decl,
                    src_dst: RegId::new(3),
                    args: HirCallArgs {
                        pipeline_input: Some(RegId::new(2)),
                        ..HirCallArgs::default()
                    },
                },
            ],
            terminator: HirTerminator::Return { src: RegId::new(3) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 4,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_runtime_bits_binary_list_length_program(
    bits_decl: DeclId,
    length_decl: DeclId,
    random_decl: DeclId,
    target: i64,
) -> HirProgram {
    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: vec![
                HirStmt::LoadLiteral {
                    dst: RegId::new(0),
                    lit: HirLiteral::List { capacity: 1 },
                },
                HirStmt::Call {
                    decl_id: random_decl,
                    src_dst: RegId::new(1),
                    args: HirCallArgs::default(),
                },
                HirStmt::ListPush {
                    src_dst: RegId::new(0),
                    item: RegId::new(1),
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(2),
                    lit: HirLiteral::Int(target),
                },
                HirStmt::Call {
                    decl_id: bits_decl,
                    src_dst: RegId::new(3),
                    args: HirCallArgs {
                        pipeline_input: Some(RegId::new(0)),
                        positional: vec![RegId::new(2)],
                        ..HirCallArgs::default()
                    },
                },
                HirStmt::Call {
                    decl_id: length_decl,
                    src_dst: RegId::new(4),
                    args: HirCallArgs {
                        pipeline_input: Some(RegId::new(3)),
                        ..HirCallArgs::default()
                    },
                },
            ],
            terminator: HirTerminator::Return { src: RegId::new(4) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 5,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_runtime_bits_not_list_length_program(
    bits_decl: DeclId,
    length_decl: DeclId,
    random_decl: DeclId,
    signed: bool,
) -> HirProgram {
    make_runtime_bits_not_list_length_program_with_number_bytes(
        bits_decl,
        length_decl,
        random_decl,
        signed,
        None,
    )
}

fn make_runtime_bits_not_list_length_program_with_number_bytes(
    bits_decl: DeclId,
    length_decl: DeclId,
    random_decl: DeclId,
    signed: bool,
    number_bytes: Option<i64>,
) -> HirProgram {
    let mut stmts = vec![
        HirStmt::LoadLiteral {
            dst: RegId::new(0),
            lit: HirLiteral::List { capacity: 1 },
        },
        HirStmt::Call {
            decl_id: random_decl,
            src_dst: RegId::new(1),
            args: HirCallArgs::default(),
        },
        HirStmt::ListPush {
            src_dst: RegId::new(0),
            item: RegId::new(1),
        },
    ];
    let named = if let Some(number_bytes) = number_bytes {
        stmts.push(HirStmt::LoadLiteral {
            dst: RegId::new(2),
            lit: HirLiteral::Int(number_bytes),
        });
        vec![(b"number-bytes".to_vec(), RegId::new(2))]
    } else {
        Vec::new()
    };

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: {
                stmts.push(HirStmt::Call {
                    decl_id: bits_decl,
                    src_dst: RegId::new(3),
                    args: HirCallArgs {
                        pipeline_input: Some(RegId::new(0)),
                        named,
                        flags: signed.then(|| b"signed".to_vec()).into_iter().collect(),
                        ..HirCallArgs::default()
                    },
                });
                stmts.push(HirStmt::Call {
                    decl_id: length_decl,
                    src_dst: RegId::new(4),
                    args: HirCallArgs {
                        pipeline_input: Some(RegId::new(3)),
                        ..HirCallArgs::default()
                    },
                });
                stmts
            },
            terminator: HirTerminator::Return { src: RegId::new(4) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 5,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_runtime_bits_shift_signed_i64_list_length_program(
    bits_decl: DeclId,
    length_decl: DeclId,
    random_decl: DeclId,
    shift_count: i64,
) -> HirProgram {
    make_runtime_bits_shift_list_length_program(
        bits_decl,
        length_decl,
        random_decl,
        shift_count,
        true,
        Some(8),
    )
}

fn make_runtime_bits_shift_list_length_program(
    bits_decl: DeclId,
    length_decl: DeclId,
    random_decl: DeclId,
    shift_count: i64,
    signed: bool,
    number_bytes: Option<i64>,
) -> HirProgram {
    let mut stmts = vec![
        HirStmt::LoadLiteral {
            dst: RegId::new(0),
            lit: HirLiteral::List { capacity: 1 },
        },
        HirStmt::Call {
            decl_id: random_decl,
            src_dst: RegId::new(1),
            args: HirCallArgs::default(),
        },
        HirStmt::ListPush {
            src_dst: RegId::new(0),
            item: RegId::new(1),
        },
        HirStmt::LoadLiteral {
            dst: RegId::new(2),
            lit: HirLiteral::Int(shift_count),
        },
    ];
    let named = if let Some(number_bytes) = number_bytes {
        stmts.push(HirStmt::LoadLiteral {
            dst: RegId::new(3),
            lit: HirLiteral::Int(number_bytes),
        });
        vec![(b"number-bytes".to_vec(), RegId::new(3))]
    } else {
        Vec::new()
    };

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: {
                stmts.push(HirStmt::Call {
                    decl_id: bits_decl,
                    src_dst: RegId::new(4),
                    args: HirCallArgs {
                        pipeline_input: Some(RegId::new(0)),
                        positional: vec![RegId::new(2)],
                        named,
                        flags: signed.then(|| b"signed".to_vec()).into_iter().collect(),
                        ..HirCallArgs::default()
                    },
                });
                stmts.push(HirStmt::Call {
                    decl_id: length_decl,
                    src_dst: RegId::new(5),
                    args: HirCallArgs {
                        pipeline_input: Some(RegId::new(4)),
                        ..HirCallArgs::default()
                    },
                });
                stmts
            },
            terminator: HirTerminator::Return { src: RegId::new(5) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 6,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

#[test]
fn test_lower_math_abs_on_runtime_stack_numeric_list() {
    let abs_decl = DeclId::new(268);
    let length_decl = DeclId::new(269);
    let random_decl = DeclId::new(270);
    let hir = make_runtime_math_unary_list_length_program(abs_decl, length_decl, random_decl);
    let decl_names = HashMap::from([
        (abs_decl, "math abs".to_string()),
        (length_decl, "length".to_string()),
        (random_decl, "random int".to_string()),
    ]);

    let result = lower_hir_to_mir_with_hints(
        &hir,
        None,
        &decl_names,
        None,
        &HashMap::new(),
        &HashMap::new(),
    )
    .expect("math abs should lower on runtime stack-backed numeric lists");
    let instructions = result
        .program
        .main
        .blocks
        .iter()
        .flat_map(|block| block.instructions.iter())
        .collect::<Vec<_>>();

    assert!(
        instructions.iter().any(|inst| matches!(
            inst,
            MirInst::UnaryOp {
                op: UnaryOpKind::Neg,
                ..
            }
        )),
        "expected runtime math abs to emit a negation path"
    );
    assert!(
        instructions
            .iter()
            .any(|inst| matches!(inst, MirInst::ListPush { .. })),
        "expected runtime math abs to materialize an output list"
    );
    compile_mir_to_ebpf_with_hints(&result.program, None, Some(&result.type_hints))
        .expect("runtime math abs output consumed by length should compile");
}

