fn make_bytes_predicate_program(decl_id: DeclId, input: Vec<u8>, pattern: Vec<u8>) -> HirProgram {
    make_bytes_arg_pipeline_call_program_with_flags(decl_id, input, pattern, Vec::new())
}

fn make_bytes_arg_pipeline_call_program_with_flags(
    decl_id: DeclId,
    input: Vec<u8>,
    pattern: Vec<u8>,
    flags: Vec<Vec<u8>>,
) -> HirProgram {
    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: vec![
                HirStmt::LoadLiteral {
                    dst: RegId::new(0),
                    lit: HirLiteral::Binary(input),
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(1),
                    lit: HirLiteral::Binary(pattern),
                },
                HirStmt::Call {
                    decl_id,
                    src_dst: RegId::new(2),
                    args: HirCallArgs {
                        positional: vec![RegId::new(1)],
                        pipeline_input: Some(RegId::new(0)),
                        flags,
                        ..HirCallArgs::default()
                    },
                },
            ],
            terminator: HirTerminator::Return { src: RegId::new(2) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 3,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_bytes_list_predicate_get_program(
    predicate_decl: DeclId,
    get_decl: DeclId,
    input: Vec<Vec<u8>>,
    pattern: Vec<u8>,
    index: i64,
) -> HirProgram {
    make_bytes_list_arg_get_program_with_flags(
        predicate_decl,
        get_decl,
        input,
        pattern,
        Vec::new(),
        index,
    )
}

fn make_bytes_list_arg_get_program_with_flags(
    decl_id: DeclId,
    get_decl: DeclId,
    input: Vec<Vec<u8>>,
    pattern: Vec<u8>,
    flags: Vec<Vec<u8>>,
    index: i64,
) -> HirProgram {
    let input_values = input
        .into_iter()
        .map(|item| Value::binary(item, Span::test_data()))
        .collect::<Vec<_>>();
    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: vec![
                HirStmt::LoadValue {
                    dst: RegId::new(0),
                    val: Box::new(Value::list(input_values, Span::test_data())),
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(1),
                    lit: HirLiteral::Binary(pattern),
                },
                HirStmt::Call {
                    decl_id,
                    src_dst: RegId::new(2),
                    args: HirCallArgs {
                        positional: vec![RegId::new(1)],
                        pipeline_input: Some(RegId::new(0)),
                        flags,
                        ..HirCallArgs::default()
                    },
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(3),
                    lit: HirLiteral::Int(index),
                },
                HirStmt::Call {
                    decl_id: get_decl,
                    src_dst: RegId::new(4),
                    args: HirCallArgs {
                        positional: vec![RegId::new(3)],
                        pipeline_input: Some(RegId::new(2)),
                        ..HirCallArgs::default()
                    },
                },
            ],
            terminator: HirTerminator::Return { src: RegId::new(4) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 5,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_bytes_index_of_all_join_starts_with_program(
    index_of_decl: DeclId,
    join_decl: DeclId,
    starts_with_decl: DeclId,
    input: Vec<u8>,
    pattern: Vec<u8>,
    flags: Vec<Vec<u8>>,
    expected_prefix: &str,
) -> HirProgram {
    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: vec![
                HirStmt::LoadLiteral {
                    dst: RegId::new(0),
                    lit: HirLiteral::Binary(input),
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(1),
                    lit: HirLiteral::Binary(pattern),
                },
                HirStmt::Call {
                    decl_id: index_of_decl,
                    src_dst: RegId::new(2),
                    args: HirCallArgs {
                        positional: vec![RegId::new(1)],
                        pipeline_input: Some(RegId::new(0)),
                        flags,
                        ..HirCallArgs::default()
                    },
                },
                HirStmt::LoadValue {
                    dst: RegId::new(3),
                    val: Box::new(Value::string("-", Span::test_data())),
                },
                HirStmt::Call {
                    decl_id: join_decl,
                    src_dst: RegId::new(4),
                    args: HirCallArgs {
                        positional: vec![RegId::new(3)],
                        pipeline_input: Some(RegId::new(2)),
                        ..HirCallArgs::default()
                    },
                },
                HirStmt::LoadValue {
                    dst: RegId::new(5),
                    val: Box::new(Value::string(expected_prefix, Span::test_data())),
                },
                HirStmt::Call {
                    decl_id: starts_with_decl,
                    src_dst: RegId::new(6),
                    args: HirCallArgs {
                        positional: vec![RegId::new(5)],
                        pipeline_input: Some(RegId::new(4)),
                        ..HirCallArgs::default()
                    },
                },
            ],
            terminator: HirTerminator::Return { src: RegId::new(6) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 7,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_bytes_index_of_all_length_program(
    index_of_decl: DeclId,
    length_decl: DeclId,
    input: Vec<u8>,
    pattern: Vec<u8>,
) -> HirProgram {
    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: vec![
                HirStmt::LoadLiteral {
                    dst: RegId::new(0),
                    lit: HirLiteral::Binary(input),
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(1),
                    lit: HirLiteral::Binary(pattern),
                },
                HirStmt::Call {
                    decl_id: index_of_decl,
                    src_dst: RegId::new(2),
                    args: HirCallArgs {
                        positional: vec![RegId::new(1)],
                        pipeline_input: Some(RegId::new(0)),
                        flags: vec![b"all".to_vec()],
                        ..HirCallArgs::default()
                    },
                },
                HirStmt::Call {
                    decl_id: length_decl,
                    src_dst: RegId::new(3),
                    args: HirCallArgs {
                        pipeline_input: Some(RegId::new(2)),
                        ..HirCallArgs::default()
                    },
                },
            ],
            terminator: HirTerminator::Return { src: RegId::new(3) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 4,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

#[test]
fn test_lower_bytes_starts_with_on_binary_returns_true() {
    let bytes_starts_with_decl = DeclId::new(212);
    let hir = make_bytes_predicate_program(bytes_starts_with_decl, vec![1, 2, 3], vec![1, 2]);
    let decl_names = HashMap::from([(bytes_starts_with_decl, "bytes starts-with".to_string())]);

    let result = lower_hir_to_mir_with_hints(
        &hir,
        None,
        &decl_names,
        None,
        &HashMap::new(),
        &HashMap::new(),
    )
    .expect("bytes starts-with should lower on literal binaries");

    assert!(
        result
            .program
            .main
            .blocks
            .iter()
            .flat_map(|block| block.instructions.iter())
            .any(|inst| matches!(
                inst,
                MirInst::Copy {
                    src: MirValue::Const(1),
                    ..
                }
            )),
        "expected bytes starts-with to lower to a true constant"
    );
    compile_mir_to_ebpf_with_hints(&result.program, None, Some(&result.type_hints))
        .expect("bytes starts-with on literal binaries should compile through codegen");
}

