#[test]
fn test_lower_bytes_reverse_on_binary_list_materializes_reversed_list() {
    let bytes_reverse_decl = DeclId::new(80630);
    let get_decl = DeclId::new(80631);
    let starts_with_decl = DeclId::new(80632);
    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: vec![
                HirStmt::LoadValue {
                    dst: RegId::new(0),
                    val: Box::new(Value::list(
                        vec![
                            Value::binary(vec![1, 2], Span::test_data()),
                            Value::binary(vec![3, 4], Span::test_data()),
                        ],
                        Span::test_data(),
                    )),
                },
                HirStmt::Call {
                    decl_id: bytes_reverse_decl,
                    src_dst: RegId::new(1),
                    args: HirCallArgs {
                        pipeline_input: Some(RegId::new(0)),
                        ..HirCallArgs::default()
                    },
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(2),
                    lit: HirLiteral::Int(0),
                },
                HirStmt::Call {
                    decl_id: get_decl,
                    src_dst: RegId::new(3),
                    args: HirCallArgs {
                        positional: vec![RegId::new(2)],
                        pipeline_input: Some(RegId::new(1)),
                        ..HirCallArgs::default()
                    },
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(4),
                    lit: HirLiteral::Binary(vec![2]),
                },
                HirStmt::Call {
                    decl_id: starts_with_decl,
                    src_dst: RegId::new(5),
                    args: HirCallArgs {
                        positional: vec![RegId::new(4)],
                        pipeline_input: Some(RegId::new(3)),
                        ..HirCallArgs::default()
                    },
                },
            ],
            terminator: HirTerminator::Return { src: RegId::new(5) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 6,
        file_count: 0,
    };
    let hir = HirProgram::new(func, HashMap::new(), vec![], None);
    let decl_names = HashMap::from([
        (bytes_reverse_decl, "bytes reverse".to_string()),
        (get_decl, "get".to_string()),
        (starts_with_decl, "bytes starts-with".to_string()),
    ]);

    let result = lower_hir_to_mir_with_hints(
        &hir,
        None,
        &decl_names,
        None,
        &HashMap::new(),
        &HashMap::new(),
    )
    .expect("bytes reverse should lower on compile-time binary-list input");

    assert!(
        result
            .program
            .main
            .blocks
            .iter()
            .flat_map(|block| block.instructions.iter())
            .any(|inst| matches!(
                inst,
                MirInst::Copy {
                    src: MirValue::Const(1),
                    ..
                }
            )),
        "expected reversed binary-list item to satisfy the starts-with predicate"
    );
    compile_mir_to_ebpf_with_hints(&result.program, None, Some(&result.type_hints))
        .expect("bytes reverse binary-list output should compile through codegen");
}

#[test]
fn test_lower_bytes_reverse_binary_list_folds_empty_and_unequal_results_for_bytes_collect() {
    let scenarios = [
        ("empty binary items", vec![&[][..], &[][..]], 0),
        (
            "unequal binary items",
            vec![&[0x01][..], &[0x02, 0x03][..]],
            3,
        ),
    ];

    for (index, (context, items, expected_len)) in scenarios.into_iter().enumerate() {
        let base_decl = 80700 + index * 3;
        let bytes_reverse_decl = DeclId::new(base_decl);
        let bytes_collect_decl = DeclId::new(base_decl + 1);
        let bytes_length_decl = DeclId::new(base_decl + 2);
        let hir = make_bytes_reverse_list_collect_then_length_program(
            bytes_reverse_decl,
            bytes_collect_decl,
            bytes_length_decl,
            &items,
        );
        let decl_names = HashMap::from([
            (bytes_reverse_decl, "bytes reverse".to_string()),
            (bytes_collect_decl, "bytes collect".to_string()),
            (bytes_length_decl, "bytes length".to_string()),
        ]);

        let result = lower_hir_to_mir_with_hints(
            &hir,
            None,
            &decl_names,
            None,
            &HashMap::new(),
            &HashMap::new(),
        )
        .unwrap_or_else(|err| {
            panic!("bytes reverse should fold binary-list {context} through bytes collect: {err}")
        });

        assert_program_returns_constant(&result.program, expected_len, context);
        assert_no_runtime_list_operations(&result.program, context);
        compile_mir_to_ebpf_with_hints(&result.program, None, Some(&result.type_hints))
            .unwrap_or_else(|err| {
                panic!(
                    "bytes reverse binary-list {context} consumed by bytes collect should compile: {err}"
                )
            });
    }
}

