#[test]
fn test_lower_bytes_build_materializes_binary_from_binary_and_int_args() {
    let bytes_build_decl = DeclId::new(221);
    let bytes_starts_with_decl = DeclId::new(222);
    let hir = make_bytes_build_then_starts_with_program(bytes_build_decl, bytes_starts_with_decl);
    let decl_names = HashMap::from([
        (bytes_build_decl, "bytes build".to_string()),
        (bytes_starts_with_decl, "bytes starts-with".to_string()),
    ]);

    let result = lower_hir_to_mir_with_hints(
        &hir,
        None,
        &decl_names,
        None,
        &HashMap::new(),
        &HashMap::new(),
    )
    .expect("bytes build should lower compile-time binary and integer byte arguments");

    assert!(
        result
            .readonly_globals
            .iter()
            .any(|global| global.data == vec![1, 2, 3, 4]),
        "expected bytes build to materialize concatenated binary rodata"
    );
    assert!(
        result
            .program
            .main
            .blocks
            .iter()
            .flat_map(|block| block.instructions.iter())
            .any(|inst| matches!(
                inst,
                MirInst::Copy {
                    src: MirValue::Const(1),
                    ..
                }
            )),
        "expected built bytes to satisfy the starts-with predicate"
    );
    compile_mir_to_ebpf_with_hints(&result.program, None, Some(&result.type_hints))
        .expect("bytes build output consumed by bytes starts-with should compile through codegen");
}

fn make_bytes_build_then_length_program(
    build_decl: DeclId,
    length_decl: DeclId,
    args: Vec<HirLiteral>,
) -> HirProgram {
    let arg_count = args.len() as u32;
    let build_reg = RegId::new(arg_count);
    let length_reg = RegId::new(arg_count + 1);
    let positional = (0..arg_count).map(RegId::new).collect::<Vec<_>>();

    let mut stmts = Vec::new();
    for (index, lit) in args.into_iter().enumerate() {
        stmts.push(HirStmt::LoadLiteral {
            dst: RegId::new(index as u32),
            lit,
        });
    }
    stmts.push(HirStmt::Call {
        decl_id: build_decl,
        src_dst: build_reg,
        args: HirCallArgs {
            positional,
            ..HirCallArgs::default()
        },
    });
    stmts.push(HirStmt::Call {
        decl_id: length_decl,
        src_dst: length_reg,
        args: HirCallArgs {
            pipeline_input: Some(build_reg),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: length_reg },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: arg_count + 2,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

