#[test]
fn test_lower_bytes_at_binary_list_rejects_unmaterializable_slices() {
    let scenarios = [
        (
            "empty slices",
            vec![&[0x01][..], &[0x02][..]],
            Some(1),
            Some(0),
            "bytes at requires non-empty binary list results",
        ),
        (
            "unequal slices",
            vec![&[0x01][..], &[0x02, 0x03][..]],
            Some(0),
            None,
            "bytes at requires equal-length binary list results",
        ),
    ];

    for (index, (context, items, start, end, expected_error)) in scenarios.into_iter().enumerate() {
        let bytes_at_decl = DeclId::new(662 + index * 2);
        let get_decl = DeclId::new(663 + index * 2);
        let hir = make_bytes_at_list_then_pipeline_call_program(
            bytes_at_decl,
            get_decl,
            &items,
            start,
            end,
            RangeInclusion::Inclusive,
        );
        let decl_names = HashMap::from([
            (bytes_at_decl, "bytes at".to_string()),
            (get_decl, "get".to_string()),
        ]);

        let err = match lower_hir_to_mir_with_hints(
            &hir,
            None,
            &decl_names,
            None,
            &HashMap::new(),
            &HashMap::new(),
        ) {
            Ok(_) => panic!("bytes at should reject unmaterialized {context}"),
            Err(err) => err,
        };

        assert!(
            err.to_string().contains(expected_error),
            "unexpected error for {context}: {err}"
        );
    }
}

fn make_bytes_add_then_starts_with_program(
    add_decl: DeclId,
    starts_with_decl: DeclId,
    input: Vec<u8>,
    data: Vec<u8>,
    index: Option<i64>,
    from_end: bool,
    expected_prefix: Vec<u8>,
) -> HirProgram {
    let mut stmts = vec![
        HirStmt::LoadLiteral {
            dst: RegId::new(0),
            lit: HirLiteral::Binary(input),
        },
        HirStmt::LoadLiteral {
            dst: RegId::new(1),
            lit: HirLiteral::Binary(data),
        },
    ];
    let mut named = Vec::new();
    let register_count = 6;
    if let Some(index) = index {
        stmts.push(HirStmt::LoadLiteral {
            dst: RegId::new(2),
            lit: HirLiteral::Int(index),
        });
        named.push((b"index".to_vec(), RegId::new(2)));
    }
    stmts.push(HirStmt::Call {
        decl_id: add_decl,
        src_dst: RegId::new(3),
        args: HirCallArgs {
            positional: vec![RegId::new(1)],
            named,
            pipeline_input: Some(RegId::new(0)),
            flags: if from_end {
                vec![b"end".to_vec()]
            } else {
                Vec::new()
            },
            ..HirCallArgs::default()
        },
    });
    stmts.push(HirStmt::LoadLiteral {
        dst: RegId::new(4),
        lit: HirLiteral::Binary(expected_prefix),
    });
    stmts.push(HirStmt::Call {
        decl_id: starts_with_decl,
        src_dst: RegId::new(5),
        args: HirCallArgs {
            positional: vec![RegId::new(4)],
            pipeline_input: Some(RegId::new(3)),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: RegId::new(5) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_bytes_add_list_collect_then_starts_with_program(
    add_decl: DeclId,
    collect_decl: DeclId,
    starts_with_decl: DeclId,
    items: &[&[u8]],
    data: Vec<u8>,
    index: Option<i64>,
    from_end: bool,
    expected_prefix: Vec<u8>,
) -> HirProgram {
    let item_count = items.len();
    let item_count_u32 = u32::try_from(item_count).expect("test binary-list length fits in u32");
    let mut stmts = vec![HirStmt::LoadLiteral {
        dst: RegId::new(0),
        lit: HirLiteral::List {
            capacity: item_count,
        },
    }];

    for (item_index, item) in items.iter().enumerate() {
        let item_reg = RegId::new(u32::try_from(item_index).expect("test index fits in u32") + 1);
        stmts.push(HirStmt::LoadLiteral {
            dst: item_reg,
            lit: HirLiteral::Binary(item.to_vec()),
        });
        stmts.push(HirStmt::ListPush {
            src_dst: RegId::new(0),
            item: item_reg,
        });
    }

    let data_reg = RegId::new(item_count_u32 + 1);
    let index_reg = index.map(|raw_index| {
        let reg = RegId::new(item_count_u32 + 2);
        stmts.push(HirStmt::LoadLiteral {
            dst: reg,
            lit: HirLiteral::Int(raw_index),
        });
        reg
    });
    let added_reg = RegId::new(item_count_u32 + 2 + u32::from(index_reg.is_some()));
    let collected_reg = RegId::new(added_reg.get() + 1);
    let expected_reg = RegId::new(added_reg.get() + 2);
    let starts_with_reg = RegId::new(added_reg.get() + 3);

    stmts.push(HirStmt::LoadLiteral {
        dst: data_reg,
        lit: HirLiteral::Binary(data),
    });
    stmts.push(HirStmt::Call {
        decl_id: add_decl,
        src_dst: added_reg,
        args: HirCallArgs {
            positional: vec![data_reg],
            named: index_reg
                .map(|reg| vec![(b"index".to_vec(), reg)])
                .unwrap_or_default(),
            pipeline_input: Some(RegId::new(0)),
            flags: if from_end {
                vec![b"end".to_vec()]
            } else {
                Vec::new()
            },
            ..HirCallArgs::default()
        },
    });
    stmts.push(HirStmt::Call {
        decl_id: collect_decl,
        src_dst: collected_reg,
        args: HirCallArgs {
            pipeline_input: Some(added_reg),
            ..HirCallArgs::default()
        },
    });
    stmts.push(HirStmt::LoadLiteral {
        dst: expected_reg,
        lit: HirLiteral::Binary(expected_prefix),
    });
    stmts.push(HirStmt::Call {
        decl_id: starts_with_decl,
        src_dst: starts_with_reg,
        args: HirCallArgs {
            positional: vec![expected_reg],
            pipeline_input: Some(collected_reg),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return {
                src: starts_with_reg,
            },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: starts_with_reg.get() + 1,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_bytes_add_then_length_program(
    add_decl: DeclId,
    length_decl: DeclId,
    input: Vec<u8>,
    data: Vec<u8>,
    index: Option<i64>,
    from_end: bool,
) -> HirProgram {
    let mut stmts = vec![
        HirStmt::LoadLiteral {
            dst: RegId::new(0),
            lit: HirLiteral::Binary(input),
        },
        HirStmt::LoadLiteral {
            dst: RegId::new(1),
            lit: HirLiteral::Binary(data),
        },
    ];
    let mut named = Vec::new();
    if let Some(index) = index {
        stmts.push(HirStmt::LoadLiteral {
            dst: RegId::new(2),
            lit: HirLiteral::Int(index),
        });
        named.push((b"index".to_vec(), RegId::new(2)));
    }
    stmts.push(HirStmt::Call {
        decl_id: add_decl,
        src_dst: RegId::new(3),
        args: HirCallArgs {
            positional: vec![RegId::new(1)],
            named,
            pipeline_input: Some(RegId::new(0)),
            flags: if from_end {
                vec![b"end".to_vec()]
            } else {
                Vec::new()
            },
            ..HirCallArgs::default()
        },
    });
    stmts.push(HirStmt::Call {
        decl_id: length_decl,
        src_dst: RegId::new(4),
        args: HirCallArgs {
            pipeline_input: Some(RegId::new(3)),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: RegId::new(4) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 5,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

