#[test]
fn test_lower_bytes_add_binary_list_rejects_unmaterializable_results() {
    let scenarios = [
        (
            "empty binary outputs",
            vec![&[][..], &[][..]],
            "bytes add requires non-empty binary list results",
        ),
        (
            "unequal binary outputs",
            vec![&[0x01][..], &[0x02, 0x03][..]],
            "bytes add requires equal-length binary list results",
        ),
    ];

    for (index, (context, items, expected_error)) in scenarios.into_iter().enumerate() {
        let bytes_add_decl = DeclId::new(687 + index * 2);
        let get_decl = DeclId::new(688 + index * 2);
        let hir = make_bytes_add_list_then_pipeline_call_program(
            bytes_add_decl,
            get_decl,
            &items,
            Vec::new(),
            None,
            false,
        );
        let decl_names = HashMap::from([
            (bytes_add_decl, "bytes add".to_string()),
            (get_decl, "get".to_string()),
        ]);

        let err = match lower_hir_to_mir_with_hints(
            &hir,
            None,
            &decl_names,
            None,
            &HashMap::new(),
            &HashMap::new(),
        ) {
            Ok(_) => panic!("bytes add should reject unmaterialized {context}"),
            Err(err) => err,
        };

        assert!(
            err.to_string().contains(expected_error),
            "unexpected error for {context}: {err}"
        );
    }
}

#[test]
fn test_lower_bytes_add_from_end_materializes_inserted_binary() {
    let bytes_add_decl = DeclId::new(229);
    let bytes_starts_with_decl = DeclId::new(230);
    let hir = make_bytes_add_then_starts_with_program(
        bytes_add_decl,
        bytes_starts_with_decl,
        vec![1, 2, 5],
        vec![3, 4],
        Some(1),
        true,
        vec![1, 2, 3, 4],
    );
    let decl_names = HashMap::from([
        (bytes_add_decl, "bytes add".to_string()),
        (bytes_starts_with_decl, "bytes starts-with".to_string()),
    ]);

    let result = lower_hir_to_mir_with_hints(
        &hir,
        None,
        &decl_names,
        None,
        &HashMap::new(),
        &HashMap::new(),
    )
    .expect("bytes add --end should lower compile-time binary input and data");

    assert!(
        result
            .readonly_globals
            .iter()
            .any(|global| global.data == vec![1, 2, 3, 4, 5]),
        "expected bytes add --end --index to materialize end-relative insertion"
    );
    compile_mir_to_ebpf_with_hints(&result.program, None, Some(&result.type_hints)).expect(
        "bytes add --end output consumed by bytes starts-with should compile through codegen",
    );
}

