fn make_bytes_pattern_transform_list_get_then_pipeline_call_program(
    transform_decl: DeclId,
    get_decl: DeclId,
    consumer_decl: DeclId,
    command: &str,
    items: &[&[u8]],
    pattern: Vec<u8>,
    replacement: Option<Vec<u8>>,
    flags: Vec<&str>,
    get_index: i64,
    consumer_arg: Option<HirLiteral>,
) -> HirProgram {
    let mut stmts = Vec::new();
    let (input_reg, positional, next_reg) =
        make_bytes_pattern_transform_list_prefix(&mut stmts, items, pattern, replacement, command);
    let transformed_reg = RegId::new(next_reg);
    let get_index_reg = RegId::new(next_reg + 1);
    let get_reg = RegId::new(next_reg + 2);

    stmts.push(HirStmt::Call {
        decl_id: transform_decl,
        src_dst: transformed_reg,
        args: HirCallArgs {
            positional,
            pipeline_input: Some(input_reg),
            flags: flags
                .into_iter()
                .map(|flag| flag.as_bytes().to_vec())
                .collect(),
            ..HirCallArgs::default()
        },
    });
    stmts.push(HirStmt::LoadLiteral {
        dst: get_index_reg,
        lit: HirLiteral::Int(get_index),
    });
    stmts.push(HirStmt::Call {
        decl_id: get_decl,
        src_dst: get_reg,
        args: HirCallArgs {
            positional: vec![get_index_reg],
            pipeline_input: Some(transformed_reg),
            ..HirCallArgs::default()
        },
    });

    let mut consumer_args = HirCallArgs {
        pipeline_input: Some(get_reg),
        ..HirCallArgs::default()
    };
    let consumer_reg = if let Some(arg) = consumer_arg {
        let arg_reg = RegId::new(get_reg.get() + 1);
        stmts.push(HirStmt::LoadLiteral {
            dst: arg_reg,
            lit: arg,
        });
        consumer_args.positional.push(arg_reg);
        RegId::new(get_reg.get() + 2)
    } else {
        RegId::new(get_reg.get() + 1)
    };
    stmts.push(HirStmt::Call {
        decl_id: consumer_decl,
        src_dst: consumer_reg,
        args: consumer_args,
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: consumer_reg },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: consumer_reg.get() + 1,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_bytes_pattern_transform_list_access_then_pipeline_call_program(
    transform_decl: DeclId,
    access_decl: DeclId,
    consumer_decl: DeclId,
    command: &str,
    items: &[&[u8]],
    pattern: Vec<u8>,
    replacement: Option<Vec<u8>>,
    flags: Vec<&str>,
    consumer_arg: Option<HirLiteral>,
) -> HirProgram {
    let mut stmts = Vec::new();
    let (input_reg, positional, next_reg) =
        make_bytes_pattern_transform_list_prefix(&mut stmts, items, pattern, replacement, command);
    let transformed_reg = RegId::new(next_reg);
    let access_reg = RegId::new(next_reg + 1);

    stmts.push(HirStmt::Call {
        decl_id: transform_decl,
        src_dst: transformed_reg,
        args: HirCallArgs {
            positional,
            pipeline_input: Some(input_reg),
            flags: flags
                .into_iter()
                .map(|flag| flag.as_bytes().to_vec())
                .collect(),
            ..HirCallArgs::default()
        },
    });
    stmts.push(HirStmt::Call {
        decl_id: access_decl,
        src_dst: access_reg,
        args: HirCallArgs {
            pipeline_input: Some(transformed_reg),
            ..HirCallArgs::default()
        },
    });

    let mut consumer_args = HirCallArgs {
        pipeline_input: Some(access_reg),
        ..HirCallArgs::default()
    };
    let consumer_reg = if let Some(arg) = consumer_arg {
        let arg_reg = RegId::new(access_reg.get() + 1);
        stmts.push(HirStmt::LoadLiteral {
            dst: arg_reg,
            lit: arg,
        });
        consumer_args.positional.push(arg_reg);
        RegId::new(access_reg.get() + 2)
    } else {
        RegId::new(access_reg.get() + 1)
    };
    stmts.push(HirStmt::Call {
        decl_id: consumer_decl,
        src_dst: consumer_reg,
        args: consumer_args,
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: consumer_reg },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: consumer_reg.get() + 1,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

#[test]
fn test_lower_bytes_remove_materializes_first_removed_binary() {
    let bytes_remove_decl = DeclId::new(233);
    let bytes_starts_with_decl = DeclId::new(234);
    let hir = make_bytes_pattern_transform_then_starts_with_program(
        bytes_remove_decl,
        bytes_starts_with_decl,
        "bytes remove",
        vec![0x10, 0xaa, 0xff, 0xaa, 0xff],
        vec![0x10, 0xaa],
        None,
        Vec::new(),
        vec![0xff, 0xaa],
    );
    let decl_names = HashMap::from([
        (bytes_remove_decl, "bytes remove".to_string()),
        (bytes_starts_with_decl, "bytes starts-with".to_string()),
    ]);

    let result = lower_hir_to_mir_with_hints(
        &hir,
        None,
        &decl_names,
        None,
        &HashMap::new(),
        &HashMap::new(),
    )
    .expect("bytes remove should lower compile-time binary input and pattern");

    assert!(
        result
            .readonly_globals
            .iter()
            .any(|global| global.data == vec![0xff, 0xaa, 0xff]),
        "expected bytes remove to materialize binary with first match removed"
    );
    compile_mir_to_ebpf_with_hints(&result.program, None, Some(&result.type_hints))
        .expect("bytes remove output consumed by bytes starts-with should compile through codegen");
}

