fn make_binary_list_builder_item_transform_collect_then_starts_with_program(
    transform_decl: DeclId,
    collect_decl: DeclId,
    starts_with_decl: DeclId,
    items: &[&[u8]],
    item: Vec<u8>,
    expected_prefix: Vec<u8>,
) -> HirProgram {
    let item_count = items.len();
    let mut stmts = vec![HirStmt::LoadLiteral {
        dst: RegId::new(0),
        lit: HirLiteral::List {
            capacity: item_count,
        },
    }];
    for (index, item) in items.iter().enumerate() {
        let item_reg = RegId::new(u32::try_from(index).expect("test index fits in u32") + 1);
        stmts.push(HirStmt::LoadLiteral {
            dst: item_reg,
            lit: HirLiteral::Binary(item.to_vec()),
        });
        stmts.push(HirStmt::ListPush {
            src_dst: RegId::new(0),
            item: item_reg,
        });
    }
    let transform_item_reg =
        RegId::new(u32::try_from(item_count).expect("test length fits in u32") + 1);
    let transform_reg = RegId::new(transform_item_reg.get() + 1);
    let collect_reg = RegId::new(transform_item_reg.get() + 2);
    let expected_reg = RegId::new(transform_item_reg.get() + 3);
    let starts_with_reg = RegId::new(transform_item_reg.get() + 4);
    stmts.push(HirStmt::LoadLiteral {
        dst: transform_item_reg,
        lit: HirLiteral::Binary(item),
    });
    stmts.push(HirStmt::Call {
        decl_id: transform_decl,
        src_dst: transform_reg,
        args: HirCallArgs {
            positional: vec![transform_item_reg],
            pipeline_input: Some(RegId::new(0)),
            ..HirCallArgs::default()
        },
    });
    stmts.push(HirStmt::Call {
        decl_id: collect_decl,
        src_dst: collect_reg,
        args: HirCallArgs {
            pipeline_input: Some(transform_reg),
            ..HirCallArgs::default()
        },
    });
    stmts.push(HirStmt::LoadLiteral {
        dst: expected_reg,
        lit: HirLiteral::Binary(expected_prefix),
    });
    stmts.push(HirStmt::Call {
        decl_id: starts_with_decl,
        src_dst: starts_with_reg,
        args: HirCallArgs {
            positional: vec![expected_reg],
            pipeline_input: Some(collect_reg),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return {
                src: starts_with_reg,
            },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: starts_with_reg.get() + 1,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_binary_list_builder_item_access_then_starts_with_program(
    access_decl: DeclId,
    starts_with_decl: DeclId,
    items: &[&[u8]],
    index: Option<i64>,
    expected_prefix: Vec<u8>,
) -> HirProgram {
    let item_count = items.len();
    let item_count_u32 = u32::try_from(item_count).expect("test length fits in u32");
    let mut stmts = vec![HirStmt::LoadLiteral {
        dst: RegId::new(0),
        lit: HirLiteral::List {
            capacity: item_count,
        },
    }];
    for (item_index, item) in items.iter().enumerate() {
        let item_reg = RegId::new(u32::try_from(item_index).expect("test index fits in u32") + 2);
        stmts.push(HirStmt::LoadLiteral {
            dst: item_reg,
            lit: HirLiteral::Binary(item.to_vec()),
        });
        stmts.push(HirStmt::ListPush {
            src_dst: RegId::new(0),
            item: item_reg,
        });
    }

    let index_reg = index.map(|raw_index| {
        let reg = RegId::new(item_count_u32 + 2);
        stmts.push(HirStmt::LoadLiteral {
            dst: reg,
            lit: HirLiteral::Int(raw_index),
        });
        reg
    });
    let prefix_reg = RegId::new(item_count_u32 + 2 + u32::from(index_reg.is_some()));
    stmts.push(HirStmt::Call {
        decl_id: access_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            positional: index_reg.into_iter().collect(),
            pipeline_input: Some(RegId::new(0)),
            ..HirCallArgs::default()
        },
    });
    stmts.push(HirStmt::LoadLiteral {
        dst: prefix_reg,
        lit: HirLiteral::Binary(expected_prefix),
    });
    stmts.push(HirStmt::Call {
        decl_id: starts_with_decl,
        src_dst: RegId::new(1),
        args: HirCallArgs {
            positional: vec![prefix_reg],
            pipeline_input: Some(RegId::new(1)),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: RegId::new(1) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: prefix_reg.get() + 1,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

#[test]
fn test_lower_bytes_collect_materializes_concatenated_binary() {
    let bytes_collect_decl = DeclId::new(247);
    let bytes_starts_with_decl = DeclId::new(248);
    let hir = make_bytes_collect_then_starts_with_program(
        bytes_collect_decl,
        bytes_starts_with_decl,
        vec![vec![0x11], vec![0x13], vec![0x15]],
        None,
        vec![0x11, 0x13, 0x15],
    );
    let decl_names = HashMap::from([
        (bytes_collect_decl, "bytes collect".to_string()),
        (bytes_starts_with_decl, "bytes starts-with".to_string()),
    ]);

    let result = lower_hir_to_mir_with_hints(
        &hir,
        None,
        &decl_names,
        None,
        &HashMap::new(),
        &HashMap::new(),
    )
    .expect("bytes collect should lower compile-time binary list input");

    assert!(
        result
            .readonly_globals
            .iter()
            .any(|global| global.data == vec![0x11, 0x13, 0x15]),
        "expected bytes collect to materialize concatenated binary rodata"
    );
    compile_mir_to_ebpf_with_hints(&result.program, None, Some(&result.type_hints))
        .expect("bytes collect output consumed by bytes starts-with should compile");
}

