fn make_bytes_split_collect_then_starts_with_program(
    split_decl: DeclId,
    collect_decl: DeclId,
    starts_with_decl: DeclId,
    input: Vec<u8>,
    separator: HirLiteral,
    collect_separator: Vec<u8>,
    expected_prefix: Vec<u8>,
) -> HirProgram {
    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts: vec![
                HirStmt::LoadLiteral {
                    dst: RegId::new(0),
                    lit: HirLiteral::Binary(input),
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(1),
                    lit: separator,
                },
                HirStmt::Call {
                    decl_id: split_decl,
                    src_dst: RegId::new(2),
                    args: HirCallArgs {
                        positional: vec![RegId::new(1)],
                        pipeline_input: Some(RegId::new(0)),
                        ..HirCallArgs::default()
                    },
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(3),
                    lit: HirLiteral::Binary(collect_separator),
                },
                HirStmt::Call {
                    decl_id: collect_decl,
                    src_dst: RegId::new(4),
                    args: HirCallArgs {
                        positional: vec![RegId::new(3)],
                        pipeline_input: Some(RegId::new(2)),
                        ..HirCallArgs::default()
                    },
                },
                HirStmt::LoadLiteral {
                    dst: RegId::new(5),
                    lit: HirLiteral::Binary(expected_prefix),
                },
                HirStmt::Call {
                    decl_id: starts_with_decl,
                    src_dst: RegId::new(6),
                    args: HirCallArgs {
                        positional: vec![RegId::new(5)],
                        pipeline_input: Some(RegId::new(4)),
                        ..HirCallArgs::default()
                    },
                },
            ],
            terminator: HirTerminator::Return { src: RegId::new(6) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 7,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

fn make_bytes_split_collect_then_length_program(
    split_decl: DeclId,
    collect_decl: DeclId,
    length_decl: DeclId,
    input: Vec<u8>,
    separator: HirLiteral,
    collect_separator: Option<Vec<u8>>,
) -> HirProgram {
    let mut stmts = vec![
        HirStmt::LoadLiteral {
            dst: RegId::new(0),
            lit: HirLiteral::Binary(input),
        },
        HirStmt::LoadLiteral {
            dst: RegId::new(1),
            lit: separator,
        },
        HirStmt::Call {
            decl_id: split_decl,
            src_dst: RegId::new(2),
            args: HirCallArgs {
                positional: vec![RegId::new(1)],
                pipeline_input: Some(RegId::new(0)),
                ..HirCallArgs::default()
            },
        },
    ];
    let mut collect_args = HirCallArgs {
        pipeline_input: Some(RegId::new(2)),
        ..HirCallArgs::default()
    };
    if let Some(collect_separator) = collect_separator {
        stmts.push(HirStmt::LoadLiteral {
            dst: RegId::new(3),
            lit: HirLiteral::Binary(collect_separator),
        });
        collect_args.positional.push(RegId::new(3));
    }
    stmts.push(HirStmt::Call {
        decl_id: collect_decl,
        src_dst: RegId::new(4),
        args: collect_args,
    });
    stmts.push(HirStmt::Call {
        decl_id: length_decl,
        src_dst: RegId::new(5),
        args: HirCallArgs {
            pipeline_input: Some(RegId::new(4)),
            ..HirCallArgs::default()
        },
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: RegId::new(5) },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: 6,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

