fn make_bytes_split_get_then_pipeline_call_program(
    split_decl: DeclId,
    get_decl: DeclId,
    consumer_decl: DeclId,
    input: Vec<u8>,
    separator: HirLiteral,
    index: i64,
    consumer_arg: Option<HirLiteral>,
) -> HirProgram {
    let mut stmts = vec![
        HirStmt::LoadLiteral {
            dst: RegId::new(0),
            lit: HirLiteral::Binary(input),
        },
        HirStmt::LoadLiteral {
            dst: RegId::new(1),
            lit: separator,
        },
        HirStmt::Call {
            decl_id: split_decl,
            src_dst: RegId::new(2),
            args: HirCallArgs {
                positional: vec![RegId::new(1)],
                pipeline_input: Some(RegId::new(0)),
                ..HirCallArgs::default()
            },
        },
        HirStmt::LoadLiteral {
            dst: RegId::new(3),
            lit: HirLiteral::Int(index),
        },
        HirStmt::Call {
            decl_id: get_decl,
            src_dst: RegId::new(4),
            args: HirCallArgs {
                positional: vec![RegId::new(3)],
                pipeline_input: Some(RegId::new(2)),
                ..HirCallArgs::default()
            },
        },
    ];

    let mut consumer_args = HirCallArgs {
        pipeline_input: Some(RegId::new(4)),
        ..HirCallArgs::default()
    };
    let consumer_reg = if let Some(arg) = consumer_arg {
        stmts.push(HirStmt::LoadLiteral {
            dst: RegId::new(5),
            lit: arg,
        });
        consumer_args.positional.push(RegId::new(5));
        RegId::new(6)
    } else {
        RegId::new(5)
    };
    stmts.push(HirStmt::Call {
        decl_id: consumer_decl,
        src_dst: consumer_reg,
        args: consumer_args,
    });

    let func = HirFunction {
        blocks: vec![HirBlock {
            id: HirBlockId(0),
            stmts,
            terminator: HirTerminator::Return { src: consumer_reg },
        }],
        entry: HirBlockId(0),
        spans: Vec::new(),
        ast: Vec::new(),
        comments: Vec::new(),
        register_count: consumer_reg.get() + 1,
        file_count: 0,
    };
    HirProgram::new(func, HashMap::new(), vec![], None)
}

